                if dst == hub:
                    continue
                if dst not in hub_dist:
                    valid = False
                    break
                total_cost += hub_dist[dst] * num_partitions

                # Reconstruct hub->dst path
                path = []
                cur = dst
                while cur != hub:
                    path.append(cur)
                    cur = hub_prev[cur]
                path.append(hub)
                paths[dst] = path[::-1]

            if valid and total_cost < best_cost:
                best_cost = total_cost
                best_hub = hub
                best_hub_paths = paths

        if best_hub:
            cloud_hubs[cloud] = best_hub
            hub_paths[best_hub] = best_hub_paths

    # Compute costs for comparison
    direct_cost = sum(src_dist.get(d, float('inf')) * num_partitions for d in dsts)

    hub_cost = 0
    for cloud, dests in cloud_dests.items():
        if cloud in cloud_hubs:
            hub = cloud_hubs[cloud]
            hub_cost += src_dist[hub] * num_partitions
            for dst in dests:
                if dst != hub:
                    # Find path cost from hub to dst
                    try:
                        path_cost = nx.dijkstra_path_length(G, hub, dst, weight='cost')
                        hub_cost += path_cost * num_partitions
                    except:
                        hub_cost += src_dist.get(dst, float('inf')) * num_partitions
        else:
            for dst in dests:
                hub_cost += src_dist.get(dst, float('inf')) * num_partitions

    # Choose strategy
    use_hubs = hub_cost < direct_cost

    # Build paths for all partitions
    for partition in range(num_partitions):
        if use_hubs:
            # Hub-based routing
            for cloud, dests in cloud_dests.items():
                if cloud not in cloud_hubs:
                    # Direct routing for this cloud
                    for dst in dests:
                        if dst in src_paths:
                            path = src_paths[dst]
                            for i in range(len(path)-1):
                                u, v = path[i], path[i+1]
                                bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])
                    continue

                hub = cloud_hubs[cloud]

                # Add source-to-hub path (shared for all destinations in this cloud)
                if hub in src_paths:
                    src_hub_path = src_paths[hub]
                    for dst in dests:
                        for i in range(len(src_hub_path)-1):
                            u, v = src_hub_path[i], src_hub_path[i+1]
                            bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])

                # Add hub-to-destination paths
                for dst in dests:
                    if dst == hub:
                        continue

                    if hub in hub_paths and dst in hub_paths[hub]:
                        path = hub_paths[hub][dst]
                        for i in range(len(path)-1):
                            u, v = path[i], path[i+1]
                            bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])
                    else:
                        # Compute hub->dst path
                        try:
                            path = nx.dijkstra_path(G, hub, dst, weight='cost')
                            for i in range(len(path)-1):
                                u, v = path[i], path[i+1]
                                bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])
                        except:
                            # Fallback to direct
                            if dst in src_paths:
                                path = src_paths[dst]
                                for i in range(len(path)-1):
                                    u, v = path[i], path[i+1]
                                    bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])
        else:
            # Direct routing
            for dst in dsts:
                if dst in src_paths:
                    path = src_paths[dst]
                    for i in range(len(path)-1):
                        u, v = path[i], path[i+1]
                        bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])

    # Ensure all destinations have paths
    for dst in dsts:
        for partition in range(num_partitions):
            if not bc_topology.paths.get(dst, {}).get(str(partition), []):
                if dst in src_paths:
                    path = src_paths[dst]
                    for i in range(len(path)-1):
                        u, v = path[i], path[i+1]
                        bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])

    return bc_topology

