def search_algorithm(src: str, dsts: List[str], G: nx.DiGraph, num_partitions: int) -> BroadCastTopology:
    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # Precompute all-pairs shortest paths for cost
    all_nodes = list(G.nodes())
    all_pairs_cost = {}
    all_pairs_path = {}

    for node in all_nodes:
        try:
            dist, paths = nx.single_source_dijkstra(G, node, weight='cost')
            all_pairs_cost[node] = dist
            all_pairs_path[node] = paths
        except:
            all_pairs_cost[node] = {}
            all_pairs_path[node] = {}

    # Group destinations by cloud
    cloud_dests = defaultdict(list)
    for dst in dsts:
        if dst.startswith("aws"):
            cloud_dests["aws"].append(dst)
        elif dst.startswith("azure"):
            cloud_dests["azure"].append(dst)
        elif dst.startswith("gcp"):
            cloud_dests["gcp"].append(dst)

    # Compute Steiner tree approximation using minimum spanning tree heuristic
    def compute_steiner_tree(terminals: List[str]) -> Dict[str, List[str]]:
        if not terminals:
            return {}

        # Create complete graph on terminals with shortest path distances
        terminal_set = set(terminals)
        complete_graph = {}
        for t1 in terminals:
            complete_graph[t1] = {}
            for t2 in terminals:
                if t1 != t2 and t2 in all_pairs_cost.get(t1, {}):
                    complete_graph[t1][t2] = all_pairs_cost[t1][t2]

        # Minimum spanning tree on complete graph
        mst_edges = []
        visited = set()
        start = terminals[0]
        visited.add(start)

        while len(visited) < len(terminals):
            min_edge = None
            min_cost = float('inf')
            for u in visited:
                for v, cost in complete_graph.get(u, {}).items():
                    if v not in visited and cost < min_cost:
                        min_cost = cost
                        min_edge = (u, v, cost)
            if min_edge:
                u, v, _ = min_edge
                visited.add(v)
                mst_edges.append((u, v))

        # Reconstruct Steiner tree by unioning shortest paths
        steiner_paths = {}
        for u, v in mst_edges:
            if u in all_pairs_path and v in all_pairs_path[u]:
                path = all_pairs_path[u][v]
                # Store path for each pair
                steiner_paths[(u, v)] = path

        return steiner_paths

    # Compute Steiner trees for each cloud
    cloud_steiner_trees = {}
    for cloud in ["aws", "azure", "gcp"]:
        if cloud_dests[cloud]:
            cloud_steiner_trees[cloud] = compute_steiner_tree(cloud_dests[cloud])
        else:
            cloud_steiner_trees[cloud] = {}

    # Find best entry point for each cloud (minimize cost to Steiner tree)
    cloud_entry_points = {}
    entry_costs = {}

    for cloud in ["aws", "azure", "gcp"]:
        if not cloud_dests[cloud]:
            cloud_entry_points[cloud] = None
            entry_costs[cloud] = float('inf')
            continue

        best_entry = None
        best_cost = float('inf')
        best_steiner_cost = float('inf')

        cloud_nodes = [n for n in all_nodes if n.startswith(cloud)]
        for entry in cloud_nodes:
            if entry not in all_pairs_cost.get(src, {}):
                continue

            # Cost from source to entry
            src_to_entry = all_pairs_cost[src][entry]

            # Cost from entry to all destinations in cloud via Steiner tree
            steiner_cost = 0
            valid = True

            # For each edge in Steiner tree, find cost from entry
            steiner_edges = list(cloud_steiner_trees[cloud].keys())
            if not steiner_edges:
                # Single destination or no edges
                for dst in cloud_dests[cloud]:
                    if dst != entry:
                        if dst in all_pairs_cost.get(entry, {}):
                            steiner_cost += all_pairs_cost[entry][dst]
                        else:
                            valid = False
                            break
            else:
                # Calculate total cost from entry to cover all Steiner tree edges
                edge_costs = {}
                for u, v in steiner_edges:
                    # Cost from entry to u and v
                    if u in all_pairs_cost.get(entry, {}) and v in all_pairs_cost.get(entry, {}):
                        cost_to_u = all_pairs_cost[entry][u]
                        cost_to_v = all_pairs_cost[entry][v]
                        edge_costs[(u, v)] = min(cost_to_u, cost_to_v)
                    else:
                        valid = False
                        break

                if valid:
                    # Sum of minimum costs to cover all edges
                    steiner_cost = sum(edge_costs.values())

            if valid and src_to_entry + steiner_cost < best_cost:
                best_cost = src_to_entry + steiner_cost
                best_entry = entry
                best_steiner_cost = steiner_cost

        cloud_entry_points[cloud] = best_entry
        entry_costs[cloud] = best_cost if best_entry else float('inf')

    # Calculate direct costs
    direct_costs = {}
    for dst in dsts:
        direct_costs[dst] = all_pairs_cost.get(src, {}).get(dst, float('inf'))

    # Calculate total costs for different strategies
    total_direct = sum(direct_costs.get(d, 0) for d in dsts)
    total_steiner = sum(entry_costs.get(c, 0) for c in ["aws", "azure", "gcp"])

    # Determine optimal strategy mix based on cost savings
    # Use more Steiner routing when it provides significant savings
    steiner_ratio = 0.0
    if total_direct > 0:
        steiner_savings = total_direct - total_steiner
        max_savings = total_direct * 0.5  # Cap at 50% savings
        if steiner_savings > 0:
            steiner_ratio = min(steiner_savings / max_savings, 1.0)

    # For each partition, determine routing strategy
    for partition in range(num_partitions):
        # Use a deterministic but varied approach based on partition index
        use_steiner = False

        if num_partitions == 1:
            # Single partition: choose best overall
            use_steiner = total_steiner < total_direct
        else:
            # Multiple partitions: mix strategies
            # Use Steiner for first p% of partitions where p = steiner_ratio
            steiner_count = int(num_partitions * steiner_ratio)
            use_steiner = partition < steiner_count

        if use_steiner:
            # Use Steiner tree routing
            for cloud in ["aws", "azure", "gcp"]:
                entry = cloud_entry_points[cloud]
                if not entry or entry not in all_pairs_path.get(src, {}):
                    # Fallback to direct for this cloud
                    for dst in cloud_dests[cloud]:
                        if dst in all_pairs_path.get(src, {}):
                            path = all_pairs_path[src][dst]
                            for i in range(len(path)-1):
                                u, v = path[i], path[i+1]
                                bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])
                    continue

                # Path from source to entry point
                src_to_entry = all_pairs_path[src][entry]
                # Add this path to all destinations in this cloud
                for dst in cloud_dests[cloud]:
                    for i in range(len(src_to_entry)-1):
                        u, v = src_to_entry[i], src_to_entry[i+1]
                        bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])

                # Add Steiner tree edges within cloud
                steiner_edges = list(cloud_steiner_trees[cloud].keys())
                if steiner_edges:
                    # For each edge in Steiner tree, add the path
                    for u, v in steiner_edges:
                        if u in all_pairs_path and v in all_pairs_path[u]:
                            path = all_pairs_path[u][v]
                            # Determine which destinations need this edge
                            # Simple heuristic: destinations that are u or v, or in same cloud
                            for dst in cloud_dests[cloud]:
                                # Check if this edge is on path from entry to dst
                                try:
                                    entry_to_dst = nx.dijkstra_path(G, entry, dst, weight='cost')
                                    # Check if edge (u,v) is in this path
                                    for i in range(len(entry_to_dst)-1):
                                        if (entry_to_dst[i], entry_to_dst[i+1]) == (u, v):
                                            # Add this edge to destination
                                            bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])
                                            break
                                except:
                                    continue
                else:
                    # Single destination or direct connections
                    for dst in cloud_dests[cloud]:
                        if dst != entry:
                            try:
                                path = nx.dijkstra_path(G, entry, dst, weight='cost')
                                for i in range(len(path)-1):
                                    u, v = path[i], path[i+1]
                                    bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])
                            except:
                                if dst in all_pairs_path.get(src, {}):
                                    path = all_pairs_path[src][dst]
                                    for i in range(len(path)-1):
                                        u, v = path[i], path[i+1]
                                        bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])
        else:
            # Use direct routing
            for dst in dsts:
                if dst in all_pairs_path.get(src, {}):
                    path = all_pairs_path[src][dst]
                    for i in range(len(path)-1):
                        u, v = path[i], path[i+1]
                        bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])

    # Final verification and cleanup
    for dst in dsts:
        for partition in range(num_partitions):
            if not bc_topology.paths.get(dst, {}).get(str(partition), []):
                # Ensure all destinations have at least some path
                if dst in all_pairs_path.get(src, {}):
                    path = all_pairs_path[src][dst]
                    for i in range(len(path)-1):
                        u, v = path[i], path[i+1]
                        bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])

    return bc_topology

