def search_algorithm(src: str, dsts: List[str], G: nx.DiGraph, num_partitions: int) -> BroadCastTopology:
    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # Precompute shortest paths from source to all destinations
    shortest_paths = {}
    for dst in dsts:
        if dst == src:
            continue
        try:
            path = nx.dijkstra_path(G, src, dst, weight='cost')
            shortest_paths[dst] = path
        except nx.NetworkXNoPath:
            shortest_paths[dst] = None

    # Group destinations by cloud
    cloud_dests = defaultdict(list)
    for dst in dsts:
        if dst.startswith("aws"):
            cloud_dests["aws"].append(dst)
        elif dst.startswith("azure"):
            cloud_dests["azure"].append(dst)
        elif dst.startswith("gcp"):
            cloud_dests["gcp"].append(dst)

    # Find optimal cloud hubs
    cloud_hubs = {}
    for cloud, cloud_dsts in cloud_dests.items():
        if not cloud_dsts:
            continue

        # Simple approach: pick the first destination as hub for single dest
        if len(cloud_dsts) <= 1:
            cloud_hubs[cloud] = cloud_dsts[0] if cloud_dsts else None
            continue

        # For multiple destinations, find a hub that minimizes total cost
        best_hub = None
        min_total_cost = float('inf')

        # Check all nodes in this cloud
        for node in G.nodes():
            if not node.startswith(cloud):
                continue

            try:
                # Calculate cost to reach this hub from source (for all partitions)
                hub_to_src_cost = nx.dijkstra_path_length(G, src, node, weight='cost')

                # Calculate total intra-cloud cost  
                total_intra_cost = 0
                valid = True
                for dst in cloud_dsts:
                    if dst == node:
                        continue
                    try:
                        total_intra_cost += nx.dijkstra_path_length(G, node, dst, weight='cost')
                    except nx.NetworkXNoPath:
                        valid = False
                        break

                if valid:
                    total_cost = hub_to_src_cost + total_intra_cost
                    if total_cost < min_total_cost:
                        min_total_cost = total_cost
                        best_hub = node
            except:
                continue

        cloud_hubs[cloud] = best_hub

    # Assign each partition to a path
    for partition in range(num_partitions):
        for dst in dsts:
            if dst == src:
                continue

            # Determine cloud strategy for this destination
            dst_cloud = None
            for cloud in ["aws", "azure", "gcp"]:
                if dst.startswith(cloud):
                    dst_cloud = cloud
                    break

            # Select path
            path = None
            hub = cloud_hubs.get(dst_cloud)

            # Use hub strategy if valid and not the destination itself
            if (dst_cloud and hub and dst != hub and 
                hub in shortest_paths and shortest_paths[dst]):
                try:
                    # Path: src -> hub -> dst
                    src_to_hub = shortest_paths[hub] if hub in shortest_paths else None
                    if src_to_hub and dst in shortest_paths and shortest_paths[dst]:
                        hub_to_dst = nx.dijkstra_path(G, hub, dst, weight='cost')
                        # Combine paths avoiding duplicate hub
                        if src_to_hub and len(src_to_hub) > 0:
                            if src_to_hub[-1] == hub_to_dst[0]:
                                path = src_to_hub[:-1] + hub_to_dst
                            else:
                                path = src_to_hub + hub_to_dst
                except:
                    pass

            # Fallback to direct path
            if not path and dst in shortest_paths:
                path = shortest_paths[dst]

            # Final fallback to direct path computation
            if not path:
                try:
                    path = nx.dijkstra_path(G, src, dst, weight='cost')
                except:
                    continue  # Skip if no path

            # Add path segments to topology
            for i in range(len(path) - 1):
                u, v = path[i], path[i + 1]
                if G.has_edge(u, v):
                    edge_data = G[u][v]
                    bc_topology.append_dst_partition_path(dst, partition, [u, v, edge_data])

    return bc_topology

import networkx as nx
from typing import List
