def search_algorithm(src: str, dsts: List[str], G: nx.DiGraph, num_partitions: int) -> BroadCastTopology:
    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # Precompute single-source shortest paths from source and to destinations
    # Compute forward shortest paths from source
    forward_cost = {}
    forward_path = {}
    try:
        f_dist, f_paths = nx.single_source_dijkstra(G, src, weight='cost')
        forward_cost = f_dist
        forward_path = f_paths
    except:
        forward_cost = {}
        forward_path = {}

    # Compute backward shortest paths to each destination
    backward_cost = {}
    backward_path = {}
    for dst in dsts:
        try:
            b_dist, b_paths = nx.single_source_dijkstra(G.reverse(copy=False), dst, weight='cost')
            backward_cost[dst] = b_dist
            backward_path[dst] = b_paths
        except:
            backward_cost[dst] = {}
            backward_path[dst] = {}

    # Group destinations by cloud
    cloud_dests = defaultdict(list)
    for dst in dsts:
        if dst.startswith("aws"):
            cloud_dests["aws"].append(dst)
        elif dst.startswith("azure"):
            cloud_dests["azure"].append(dst)
        elif dst.startswith("gcp"):
            cloud_dests["gcp"].append(dst)

    # For each cloud, find optimal hub that minimizes source→hub + Σ(hub→dest_in_cloud)
    cloud_hubs = {}
    hub_paths_to_dests = {}
    hub_costs = {}

    all_nodes = list(G.nodes())

    for cloud in ["aws", "azure", "gcp"]:
        dests_in_cloud = cloud_dests[cloud]
        if not dests_in_cloud:
            cloud_hubs[cloud] = None
            continue

        cloud_nodes = [n for n in all_nodes if n.startswith(cloud)]
        best_hub = None
        best_cost = float('inf')
        best_paths = {}

        for hub in cloud_nodes:
            if hub not in forward_cost:
                continue

            total_cost = forward_cost[hub] * len(dests_in_cloud)  # Each partition pays src→hub
            valid = True
            paths = {}

            for dst in dests_in_cloud:
                if dst == hub:
                    paths[dst] = []
                    continue
                if dst not in backward_cost or hub not in backward_cost[dst]:
                    valid = False
                    break
                total_cost += backward_cost[dst][hub]  # hub→dst
                # Reconstruct path from hub to dst using backward paths
                if hub in backward_path[dst]:
                    path = backward_path[dst][hub]
                    paths[dst] = list(reversed(path))
                else:
                    paths[dst] = []

            if valid and total_cost < best_cost:
                best_cost = total_cost
                best_hub = hub
                best_paths = paths

        cloud_hubs[cloud] = best_hub
        if best_hub:
            hub_paths_to_dests[best_hub] = best_paths
            hub_costs[best_hub] = best_cost

    # Compute direct routing cost (src→dest for each dest)
    direct_costs = {}
    direct_paths = {}
    for dst in dsts:
        if dst in forward_cost:
            direct_costs[dst] = forward_cost[dst] * num_partitions  # Each partition pays
            direct_paths[dst] = forward_path[dst]
        else:
            direct_costs[dst] = float('inf')

    # Compute hub routing cost
    hub_total_cost = 0
    for cloud in ["aws", "azure", "gcp"]:
        hub = cloud_hubs[cloud]
        if hub:
            hub_total_cost += hub_costs[hub]
        else:
            for dst in cloud_dests[cloud]:
                hub_total_cost += direct_costs[dst]

    # Compute hybrid cost: for each cloud, choose min(direct, hub)
    hybrid_total_cost = 0
    hybrid_strategy = {}
    for cloud in ["aws", "azure", "gcp"]:
        hub = cloud_hubs[cloud]
        dests_in_cloud = cloud_dests[cloud]

        if not dests_in_cloud:
            continue

        # Cost if using hub for this cloud
        hub_cost_for_cloud = 0
        if hub:
            hub_cost_for_cloud = hub_costs[hub]
        else:
            for dst in dests_in_cloud:
                hub_cost_for_cloud += direct_costs[dst]

        # Cost if using direct for this cloud
        direct_cost_for_cloud = sum(direct_costs[dst] for dst in dests_in_cloud)

        if hub_cost_for_cloud < direct_cost_for_cloud:
            hybrid_total_cost += hub_cost_for_cloud
            hybrid_strategy[cloud] = 'hub'
        else:
            hybrid_total_cost += direct_cost_for_cloud
            hybrid_strategy[cloud] = 'direct'

    # Choose best overall strategy
    direct_total = sum(direct_costs[dst] for dst in dsts)

    if hybrid_total_cost < min(direct_total, hub_total_cost):
        # Use hybrid: different clouds use different strategies
        for partition in range(num_partitions):
            for cloud in ["aws", "azure", "gcp"]:
                dests_in_cloud = cloud_dests[cloud]
                if not dests_in_cloud:
                    continue

                if hybrid_strategy[cloud] == 'direct':
                    for dst in dests_in_cloud:
                        if dst in direct_paths:
                            path = direct_paths[dst]
                            for i in range(len(path)-1):
                                u, v = path[i], path[i+1]
                                bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])
                else:  # hub strategy
                    hub = cloud_hubs[cloud]
                    if hub and hub in forward_path:
                        # Add source→hub path
                        src_to_hub = forward_path[hub]
                        # Add to first destination in cloud (shared segment)
                        if dests_in_cloud:
                            for i in range(len(src_to_hub)-1):
                                u, v = src_to_hub[i], src_to_hub[i+1]
                                bc_topology.append_dst_partition_path(dests_in_cloud[0], partition, [u, v, G[u][v]])

                        # Add hub→destination paths
                        for dst in dests_in_cloud:
                            if dst == hub:
                                continue
                            if hub in hub_paths_to_dests and dst in hub_paths_to_dests[hub]:
                                path = hub_paths_to_dests[hub][dst]
                                if path:
                                    for i in range(len(path)-1):
                                        u, v = path[i], path[i+1]
                                        bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])
                            else:
                                # Fallback: compute hub→dst path
                                try:
                                    path = nx.dijkstra_path(G, hub, dst, weight='cost')
                                    for i in range(len(path)-1):
                                        u, v = path[i], path[i+1]
                                        bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])
                                except:
                                    if dst in direct_paths:
                                        path = direct_paths[dst]
                                        for i in range(len(path)-1):
                                            u, v = path[i], path[i+1]
                                            bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])
                    else:
                        # Fallback to direct
                        for dst in dests_in_cloud:
                            if dst in direct_paths:
                                path = direct_paths[dst]
                                for i in range(len(path)-1):
                                    u, v = path[i], path[i+1]
                                    bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])
    elif hub_total_cost < direct_total:
        # Use hub routing for all clouds
        for partition in range(num_partitions):
            for cloud in ["aws", "azure", "gcp"]:
                dests_in_cloud = cloud_dests[cloud]
                if not dests_in_cloud:
                    continue

                hub = cloud_hubs[cloud]
                if hub and hub in forward_path:
                    # Add source→hub path
                    src_to_hub = forward_path[hub]
                    if dests_in_cloud:
                        for i in range(len(src_to_hub)-1):
                            u, v = src_to_hub[i], src_to_hub[i+1]
                            bc_topology.append_dst_partition_path(dests_in_cloud[0], partition, [u, v, G[u][v]])

                    # Add hub→destination paths
                    for dst in dests_in_cloud:
                        if dst == hub:
                            continue
                        if hub in hub_paths_to_dests and dst in hub_paths_to_dests[hub]:
                            path = hub_paths_to_dests[hub][dst]
                            if path:
                                for i in range(len(path)-1):
                                    u, v = path[i], path[i+1]
                                    bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])
                        else:
                            try:
                                path = nx.dijkstra_path(G, hub, dst, weight='cost')
                                for i in range(len(path)-1):
                                    u, v = path[i], path[i+1]
                                    bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])
                            except:
                                if dst in direct_paths:
                                    path = direct_paths[dst]
                                    for i in range(len(path)-1):
                                        u, v = path[i], path[i+1]
                                        bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])
                else:
                    for dst in dests_in_cloud:
                        if dst in direct_paths:
                            path = direct_paths[dst]
                            for i in range(len(path)-1):
                                u, v = path[i], path[i+1]
                                bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])
    else:
        # Use direct routing for all
        for partition in range(num_partitions):
            for dst in dsts:
                if dst in direct_paths:
                    path = direct_paths[dst]
                    for i in range(len(path)-1):
                        u, v = path[i], path[i+1]
                        bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])

    # Final safety check
    for dst in dsts:
        for partition in range(num_partitions):
            if not bc_topology.paths.get(dst, {}).get(str(partition), []):
                if dst in direct_paths:
                    path = direct_paths[dst]
                    for i in range(len(path)-1):
                        u, v = path[i], path[i+1]
                        bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])
                else:
                    try:
                        path = nx.dijkstra_path(G, src, dst, weight='cost')
                        for i in range(len(path)-1):
                            u, v = path[i], path[i+1]
                            bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])
                    except:
                        pass

    return bc_topology

