def search_algorithm(src: str, dsts: List[str], G: nx.DiGraph, num_partitions: int) -> BroadCastTopology:
    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # Precompute shortest paths from source to all destinations
    src_to_dst_paths = {}
    src_to_dst_costs = {}

    for dst in dsts:
        try:
            path = nx.dijkstra_path(G, src, dst, weight='cost')
            cost = sum(G[path[i]][path[i+1]]['cost'] for i in range(len(path)-1))
            src_to_dst_paths[dst] = path
            src_to_dst_costs[dst] = cost
        except nx.NetworkXNoPath:
            src_to_dst_paths[dst] = None
            src_to_dst_costs[dst] = float('inf')

    # Group destinations by cloud
    cloud_groups = defaultdict(list)
    for dst in dsts:
        if dst.startswith('aws'):
            cloud_groups['aws'].append(dst)
        elif dst.startswith('azure'):
            cloud_groups['azure'].append(dst)
        elif dst.startswith('gcp'):
            cloud_groups['gcp'].append(dst)

    # Find optimal hub for each cloud (minimize total cost)
    cloud_hubs = {}
    for cloud, nodes in cloud_groups.items():
        if not nodes:
            continue

        best_hub = None
        best_total_cost = float('inf')

        # Try each node as potential hub
        for hub_candidate in G.nodes():
            if not hub_candidate.startswith(cloud):
                continue

            # Calculate cost of routing from source to hub and hub to all destinations
            try:
                src_to_hub_path = nx.dijkstra_path(G, src, hub_candidate, weight='cost')
                src_to_hub_cost = sum(G[src_to_hub_path[i]][src_to_hub_path[i+1]]['cost'] 
                                    for i in range(len(src_to_hub_path)-1))

                total_cost = src_to_hub_cost

                # Add cost to reach each destination from hub
                valid = True
                for dst in nodes:
                    if dst == hub_candidate:
                        continue
                    try:
                        hub_to_dst_path = nx.dijkstra_path(G, hub_candidate, dst, weight='cost')
                        hub_to_dst_cost = sum(G[hub_to_dst_path[i]][hub_to_dst_path[i+1]]['cost'] 
                                            for i in range(len(hub_to_dst_path)-1))
                        total_cost += hub_to_dst_cost
                    except nx.NetworkXNoPath:
                        valid = False
                        break

                if valid and total_cost < best_total_cost:
                    best_total_cost = total_cost
                    best_hub = hub_candidate
            except nx.NetworkXNoPath:
                continue

        if best_hub:
            cloud_hubs[cloud] = best_hub

    # Create candidate paths for each destination
    candidate_paths = defaultdict(list)

    # For each destination, compute direct path and hub path
    for dst in dsts:
        candidates = []

        # Direct path
        direct_path = src_to_dst_paths.get(dst)
        if direct_path:
            candidates.append(('direct', direct_path, src_to_dst_costs[dst]))

        # Hub path if applicable
        dst_cloud = None
        if dst.startswith('aws'):
            dst_cloud = 'aws'
        elif dst.startswith('azure'):
            dst_cloud = 'azure'
        elif dst.startswith('gcp'):
            dst_cloud = 'gcp'

        if dst_cloud and dst_cloud in cloud_hubs:
            hub = cloud_hubs[dst_cloud]
            if hub != dst:
                try:
                    # Source to hub path
                    src_to_hub_path = nx.dijkstra_path(G, src, hub, weight='cost')
                    src_to_hub_cost = sum(G[src_to_hub_path[i]][src_to_hub_path[i+1]]['cost'] 
                                        for i in range(len(src_to_hub_path)-1))

                    # Hub to destination path
                    hub_to_dst_path = nx.dijkstra_path(G, hub, dst, weight='cost')
                    hub_to_dst_cost = sum(G[hub_to_dst_path[i]][hub_to_dst_path[i+1]]['cost'] 
                                        for i in range(len(hub_to_dst_path)-1))

                    # Combine paths
                    full_path = src_to_hub_path[:-1] + hub_to_dst_path
                    total_cost = src_to_hub_cost + hub_to_dst_cost

                    candidates.append(('hub', full_path, total_cost))
                except nx.NetworkXNoPath:
                    pass

        # Sort candidates and keep best ones
        candidates.sort(key=lambda x: x[2])
        candidate_paths[dst] = candidates[:min(3, len(candidates))]

    # Assign partitions to paths
    for partition in range(num_partitions):
        for dst in dsts:
            # Choose best path (rotate through candidates to diversify)
            candidates = candidate_paths[dst]
            if not candidates:
                # Fallback to direct path
                direct_path = src_to_dst_paths.get(dst)
                if direct_path:
                    path = direct_path
                else:
                    continue
            else:
                # Distribute partitions across different paths
                path_index = partition % len(candidates)
                path = candidates[path_index][1]

            # Add path segments to topology
            for i in range(len(path) - 1):
                u, v = path[i], path[i+1]
                edge_data = G[u][v]
                bc_topology.append_dst_partition_path(dst, partition, [u, v, edge_data])

    return bc_topology

