                for dst in destinations:
                    if dst == hub:
                        continue
                    try:
                        hub_to_dst = nx.dijkstra_path(G, hub, dst, weight="cost")
                        total_cost += len(hub_to_dst) - 1  # Simplified cost
                    except nx.NetworkXNoPath:
                        valid = False
                        break

            if valid and total_cost < best_total_cost:
                best_total_cost = total_cost
                best_hub = hub

        cloud_hubs[cloud] = best_hub

    # Route each partition optimally
    for partition in range(num_partitions):
        for dst in dsts:
            # Get destination's cloud
