import networkx as nx
from typing import List
from collections import defaultdict
import heapq

def search_algorithm(src: str, dsts: List[str], G: nx.DiGraph, num_partitions: int) -> BroadCastTopology:
    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # Precompute shortest paths from source to all nodes
    src_dist = {}
    src_prev = {}
    src_dist[src] = 0
    pq = [(0, src)]

    while pq:
        d, u = heapq.heappop(pq)
        if d > src_dist.get(u, float('inf')):
            continue
        for v in G[u]:
            edge_cost = G[u][v]['cost']
            new_dist = d + edge_cost
            if new_dist < src_dist.get(v, float('inf')):
                src_dist[v] = new_dist
                src_prev[v] = u
                heapq.heappush(pq, (new_dist, v))

    # Reconstruct source paths
    src_paths = {}
    for dst in dsts:
        if dst in src_dist:
            path = []
            cur = dst
            while cur != src:
                path.append(cur)
                cur = src_prev[cur]
            path.append(src)
            src_paths[dst] = path[::-1]

    # Group destinations by cloud
    cloud_dests = defaultdict(list)
    for dst in dsts:
        if dst.startswith("aws"):
            cloud_dests["aws"].append(dst)
        elif dst.startswith("azure"):
            cloud_dests["azure"].append(dst)
        elif dst.startswith("gcp"):
            cloud_dests["gcp"].append(dst)

    # For each cloud, find optimal hub and alternative hubs
    cloud_hubs = {}
    hub_alternatives = {}

    for cloud, dests in cloud_dests.items():
        if len(dests) <= 1:
            if dests:
                cloud_hubs[cloud] = dests[0]
                hub_alternatives[cloud] = [dests[0]]
            continue

        cloud_nodes = [n for n in G.nodes() if n.startswith(cloud)]
        best_hub = None
        best_cost = float('inf')
        candidate_hubs = []

        for hub in cloud_nodes:
            if hub not in src_dist:
                continue

            # Check reachability
            reachable = True
            total_cost = src_dist[hub]
            for dst in dests:
                if dst == hub:
                    continue
                try:
                    path_cost = nx.dijkstra_path_length(G, hub, dst, weight='cost')
                    total_cost += path_cost
                except:
                    reachable = False
                    break

            if not reachable:
                continue

            candidate_hubs.append((total_cost, hub))
            if total_cost < best_cost:
                best_cost = total_cost
                best_hub = hub

        if best_hub:
            cloud_hubs[cloud] = best_hub
            # Sort candidates by cost and take top 3
            candidate_hubs.sort()
            hub_alternatives[cloud] = [hub for _, hub in candidate_hubs[:min(3, len(candidate_hubs))]]
        else:
            cloud_hubs[cloud] = dests[0]
            hub_alternatives[cloud] = [dests[0]]

    # Determine optimal routing strategy per destination
    best_paths = {}

    for dst in dsts:
        # Get cloud
        dst_cloud = None
        if dst.startswith("aws"):
            dst_cloud = "aws"
        elif dst.startswith("azure"):
            dst_cloud = "azure"
        elif dst.startswith("gcp"):
            dst_cloud = "gcp"

        # Compare direct vs hub routing
        direct_cost = src_dist.get(dst, float('inf'))

        hub_cost = float('inf')
        hub_path = None

        if dst_cloud and dst_cloud in cloud_hubs:
            hub = cloud_hubs[dst_cloud]
            if hub != dst:
                try:
                    hub_to_dst_cost = nx.dijkstra_path_length(G, hub, dst, weight='cost')
                    hub_cost = src_dist.get(hub, float('inf')) + hub_to_dst_cost

                    # Build hub path
                    hub_path = []
                    if hub in src_paths:
                        hub_path.extend(src_paths[hub][:-1])

                    hub_to_dst = nx.dijkstra_path(G, hub, dst, weight='cost')
                    hub_path.extend(hub_to_dst)
                except:
                    pass

        # Choose best path
        if hub_cost < direct_cost and hub_path:
            best_paths[dst] = hub_path
        elif dst in src_paths:
            best_paths[dst] = src_paths[dst]

    # Distribute partitions with load balancing across clouds
    for partition in range(num_partitions):
        for cloud, dests in cloud_dests.items():
            if len(dests) <= 1:
                continue

            # For multi-destination clouds, use different hubs for different partitions
            if cloud in hub_alternatives and len(hub_alternatives[cloud]) > 1:
                hub_idx = partition % len(hub_alternatives[cloud])
                hub = hub_alternatives[cloud][hub_idx]

                # Source to hub path
                if hub in src_paths:
                    hub_path = src_paths[hub]
                    for i in range(len(hub_path) - 1):
                        u, v = hub_path[i], hub_path[i + 1]
                        for dst in dests:
                            bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])

                # Hub to each destination
                for dst in dests:
                    if dst == hub:
                        continue

                    try:
                        path = nx.dijkstra_path(G, hub, dst, weight='cost')
                        for i in range(len(path) - 1):
                            u, v = path[i], path[i + 1]
                            bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])
                    except:
                        # Fallback to best path
                        if dst in best_paths:
                            path = best_paths[dst]
                            for i in range(len(path) - 1):
                                u, v = path[i], path[i + 1]
                                bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])
                continue

        # Single destination or single hub clouds
        for dst in dests:
            if dst in best_paths:
                path = best_paths[dst]
                for i in range(len(path) - 1):
                    u, v = path[i], path[i + 1]
                    bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])

    return bc_topology

import networkx as nx
from typing import List, Dict, Tuple
import heapq

def search_algorithm(src: str, dsts: List[str], G: nx.DiGraph, num_partitions: int) -> BroadCastTopology:
    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # Precompute shortest paths from source to all destinations
    shortest_paths = {}
    for dst in dsts:
        try:
            path = nx.dijkstra_path(G, src, dst, weight='cost')
            shortest_paths[dst] = path
        except nx.NetworkXNoPath:
            shortest_paths[dst] = None

    # For each destination, generate diverse paths
    # Use a greedy approach: find paths with different characteristics
    dst_alternatives = {}

    for dst in dsts:
        alternatives = []
        base_path = shortest_paths.get(dst)

        if base_path:
            alternatives.append(base_path)

            # Try to find alternative paths through different intermediate nodes
            # Try paths via hub nodes that are not on the shortest path
            hub_candidates = []
            for node in G.nodes():
                if node != src and node != dst:
                    # Check if this node connects to the destination at a reasonable cost
                    try:
                        cost_to_dst = nx.dijkstra_path_length(G, node, dst, weight='cost')
                        hub_candidates.append((node, cost_to_dst))
                    except:
                        continue

            # Sort by cost to destination
            hub_candidates.sort(key=lambda x: x[1])

            # Try hub-based paths
            for hub_node, _ in hub_candidates[:3]:  # Try top 3 hubs
                try:
                    path_to_hub = nx.dijkstra_path(G, src, hub_node, weight='cost')
                    path_from_hub = nx.dijkstra_path(G, hub_node, dst, weight='cost')
                    combined_path = path_to_hub[:-1] + path_from_hub
                    # Check if this is a valid path
                    if len(combined_path) > 1 and combined_path not in alternatives:
                        alternatives.append(combined_path)
                        if len(alternatives) >= 3:
                            break
                except:
                    continue

        # If we have less than 3 alternatives, just use the base path multiple times
        if len(alternatives) < 3:
            while len(alternatives) < 3:
                alternatives.append(base_path)

        dst_alternatives[dst] = alternatives

    # Assign paths to partitions with round-robin selection
    for partition in range(num_partitions):
        for dst in dsts:
            path_idx = partition % len(dst_alternatives[dst])
            path = dst_alternatives[dst][path_idx]

            if path:
                for i in range(len(path) - 1):
                    u, v = path[i], path[i+1]
                    if G.has_edge(u, v):
                        edge_data = G[u][v]
                        bc_topology.append_dst_partition_path(dst, partition, [u, v, edge_data])

    return bc_topology

