def search_algorithm(src: str, dsts: List[str], G: nx.DiGraph, num_partitions: int) -> BroadCastTopology:
    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # Precompute all-pairs shortest paths only for needed nodes
    all_nodes = list(G.nodes())
    n = len(all_nodes)

    # Create cost and predecessor matrices for Floyd-Warshall like approach
    # but we'll use Dijkstra from each relevant node
    nodes_to_compute = set([src] + dsts)

    # Compute shortest paths from source to all nodes
    src_dist, src_paths = nx.single_source_dijkstra(G, src, weight='cost')

    # For each destination, compute shortest paths from it to all other destinations
    # (for potential multi-cast within same cloud)
    dest_to_all = {}
    for dst in dsts:
        if dst not in nodes_to_compute:
            continue
        try:
            dist, paths = nx.single_source_dijkstra(G, dst, weight='cost')
            dest_to_all[dst] = (dist, paths)
        except:
            dest_to_all[dst] = ({}, {})

    # Group destinations by cloud prefix
    cloud_groups = defaultdict(list)
    for dst in dsts:
        if dst.startswith('aws'):
            cloud_groups['aws'].append(dst)
        elif dst.startswith('azure'):
            cloud_groups['azure'].append(dst)
        elif dst.startswith('gcp'):
            cloud_groups['gcp'].append(dst)
        else:
            cloud_groups['other'].append(dst)

    # Find best intra-cloud hub for each cloud group
    cloud_hubs = {}
    hub_paths = {}

    for cloud, destinations in cloud_groups.items():
        if not destinations:
            continue

        # Find the best hub node in this cloud
        best_hub = None
        best_avg_cost = float('inf')
        best_paths_to_dests = {}

        # Try each destination as a potential hub
        for hub_candidate in destinations:
            if hub_candidate not in src_dist:
                continue

            total_cost = 0
            paths = {}
            valid = True

            # Cost from source to hub
            hub_cost = src_dist[hub_candidate]

            # Cost from hub to each destination in same cloud
            for dst in destinations:
                if dst == hub_candidate:
                    paths[dst] = [hub_candidate]
                    continue

                if dst in dest_to_all[hub_candidate][0]:
                    dst_cost = dest_to_all[hub_candidate][0][dst]
                    total_cost += dst_cost
                    paths[dst] = dest_to_all[hub_candidate][1][dst]
                else:
                    valid = False
                    break

            if valid:
                avg_cost = hub_cost + (total_cost / max(1, len(destinations) - 1))
                if avg_cost < best_avg_cost:
                    best_avg_cost = avg_cost
                    best_hub = hub_candidate
                    best_paths_to_dests = paths

        if best_hub:
            cloud_hubs[cloud] = best_hub
            hub_paths[best_hub] = best_paths_to_dests

    # For each destination, evaluate routing options
    for dst in dsts:
        # Option 1: Direct from source
        direct_cost = src_dist.get(dst, float('inf'))
        direct_path = src_paths.get(dst, [])

        # Option 2: Via cloud hub (if exists)
        hub_cost = float('inf')
        hub_path_full = []

        # Determine which cloud this destination belongs to
        cloud = None
        if dst.startswith('aws'):
            cloud = 'aws'
        elif dst.startswith('azure'):
            cloud = 'azure'
        elif dst.startswith('gcp'):
            cloud = 'gcp'

        if cloud and cloud in cloud_hubs:
            hub = cloud_hubs[cloud]
            if hub in src_dist and dst in hub_paths.get(hub, {}):
                hub_cost = src_dist[hub]
                hub_path = src_paths[hub]
                hub_to_dst_path = hub_paths[hub][dst]

                # Combine paths
                hub_path_full = hub_path[:-1] + hub_to_dst_path

        # Choose the better option for this destination
        # We'll split partitions between options if costs are close
        if direct_cost <= hub_cost * 1.1:  # Prefer direct if within 10%
            chosen_path = direct_path
        else:
            chosen_path = hub_path_full

        if not chosen_path:
            chosen_path = direct_path if direct_path else []

        # Assign partitions along the chosen path
        for partition in range(num_partitions):
            for i in range(len(chosen_path) - 1):
                u, v = chosen_path[i], chosen_path[i + 1]
                bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])

    return bc_topology

