def search_algorithm(src: str, dsts: List[str], G: nx.DiGraph, num_partitions: int) -> BroadCastTopology:
    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # Precompute all-pairs shortest paths for hub routing
    nodes = list(G.nodes())
    all_pairs_cost = {}
    all_pairs_path = {}

    for u in nodes:
        for v in nodes:
            if u == v:
                all_pairs_cost[(u, v)] = 0
                all_pairs_path[(u, v)] = [u]
            else:
                try:
                    path = nx.dijkstra_path(G, u, v, weight='cost')
                    cost = sum(G[path[i]][path[i+1]]['cost'] for i in range(len(path)-1))
                    all_pairs_cost[(u, v)] = cost
                    all_pairs_path[(u, v)] = path
                except:
                    all_pairs_cost[(u, v)] = float('inf')
                    all_pairs_path[(u, v)] = None

    # Group destinations by cloud
    cloud_dests = defaultdict(list)
    for dst in dsts:
        if dst.startswith('aws'):
            cloud_dests['aws'].append(dst)
        elif dst.startswith('azure'):
            cloud_dests['azure'].append(dst)
        elif dst.startswith('gcp'):
            cloud_dests['gcp'].append(dst)

    # Find optimal hub for each cloud
    cloud_hubs = {}
    hub_paths = {}

    for cloud, dest_list in cloud_dests.items():
        if not dest_list:
            continue

        # Consider nodes in same cloud as potential hubs
        potential_hubs = [n for n in nodes if n.startswith(cloud[:3])]
        if not potential_hubs:
            continue

        best_hub = None
        best_cost = float('inf')

        for hub in potential_hubs:
            # Check if source can reach hub
            if all_pairs_path[(src, hub)] is None:
                continue

            # Calculate total cost from hub to all destinations in this cloud
            total_hub_cost = 0
            valid = True
            for dst in dest_list:
                if all_pairs_path[(hub, dst)] is None:
                    valid = False
                    break
                total_hub_cost += all_pairs_cost[(hub, dst)]

            if not valid:
                continue

            src_to_hub_cost = all_pairs_cost[(src, hub)]
            total_cost = src_to_hub_cost * num_partitions + total_hub_cost * len(dest_list)

            if total_cost < best_cost:
                best_cost = total_cost
                best_hub = hub

        if best_hub:
            cloud_hubs[cloud] = best_hub
            # Store paths from hub to each destination
            hub_paths[cloud] = {}
            for dst in dest_list:
                hub_paths[cloud][dst] = all_pairs_path[(best_hub, dst)]

    # Generate alternative paths for each destination
    dst_paths = {}
    for dst in dsts:
        paths_for_dst = []

        # 1. Direct path from source
        direct_path = all_pairs_path[(src, dst)]
        if direct_path:
            paths_for_dst.append(('direct', direct_path))

        # 2. Path via cloud hub if available
        dst_cloud = None
        if dst.startswith('aws'):
            dst_cloud = 'aws'
        elif dst.startswith('azure'):
            dst_cloud = 'azure'
        elif dst.startswith('gcp'):
            dst_cloud = 'gcp'

        if dst_cloud and dst_cloud in cloud_hubs and dst in hub_paths.get(dst_cloud, {}):
            hub = cloud_hubs[dst_cloud]
            hub_to_dst = hub_paths[dst_cloud][dst]
            if hub_to_dst and all_pairs_path[(src, hub)]:
                # Combine paths
                via_hub_path = all_pairs_path[(src, hub)][:-1] + hub_to_dst
                paths_for_dst.append(('hub', via_hub_path))

        # 3. Try 2 alternative paths through other high-degree nodes
        high_degree_nodes = sorted(G.degree(), key=lambda x: x[1], reverse=True)[:5]
        for node, _ in high_degree_nodes:
            if node == src or node == dst or node in [src, dst]:
                continue

            if (all_pairs_path[(src, node)] and all_pairs_path[(node, dst)]):
                alt_path = all_pairs_path[(src, node)][:-1] + all_pairs_path[(node, dst)]
                if alt_path not in [p for _, p in paths_for_dst]:
                    paths_for_dst.append(('alt', alt_path))
                    if len(paths_for_dst) >= 4:  # Max 4 paths per destination
                        break

        # Calculate costs and sort
        paths_with_cost = []
        for name, path in paths_for_dst:
            cost = sum(G[path[i]][path[i+1]]['cost'] for i in range(len(path)-1))
            paths_with_cost.append((cost, path))

        # Sort by cost and keep up to 3 cheapest
        paths_with_cost.sort(key=lambda x: x[0])
        dst_paths[dst] = [path for _, path in paths_with_cost[:3]]

    # Assign partitions to paths using round-robin with cost weighting
    for partition in range(num_partitions):
        for dst in dsts:
            if dst not in dst_paths or not dst_paths[dst]:
                # Fallback to direct path
                direct_path = all_pairs_path[(src, dst)]
                if direct_path:
                    for i in range(len(direct_path)-1):
                        u, v = direct_path[i], direct_path[i+1]
                        bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])
                continue

            # Choose path based on partition and destination index
            path_options = dst_paths[dst]
            path_idx = (partition + hash(dst) % 100) % len(path_options)
            chosen_path = path_options[path_idx]

            for i in range(len(chosen_path)-1):
                u, v = chosen_path[i], chosen_path[i+1]
                bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])

    return bc_topology

