def search_algorithm(src: str, dsts: List[str], G: nx.DiGraph, num_partitions: int) -> BroadCastTopology:
    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    all_nodes = list(G.nodes())

    # Precompute all-pairs shortest paths for cost
    cost_dist = {}
    cost_pred = {}

    for node in all_nodes:
        dist = {n: float('inf') for n in all_nodes}
        pred = {n: None for n in all_nodes}
        dist[node] = 0
        pq = [(0, node)]

        while pq:
            d, u = heapq.heappop(pq)
            if d > dist[u]:
                continue
            for v in G[u]:
                edge_cost = G[u][v]['cost']
                new_dist = d + edge_cost
                if new_dist < dist[v]:
                    dist[v] = new_dist
                    pred[v] = u
                    heapq.heappush(pq, (new_dist, v))

        cost_dist[node] = dist
        cost_pred[node] = pred

    # Precompute all-pairs shortest paths for throughput (inverse)
    throughput_dist = {}

    for node in all_nodes:
        dist = {n: float('inf') for n in all_nodes}
        dist[node] = 0
        pq = [(0, node)]

        while pq:
            d, u = heapq.heappop(pq)
            if d > dist[u]:
                continue
            for v in G[u]:
                throughput = G[u][v]['throughput']
                if throughput <= 0:
                    continue
                # Use inverse throughput as weight (higher throughput = lower weight)
                weight = 1.0 / throughput
                new_dist = d + weight
                if new_dist < dist[v]:
                    dist[v] = new_dist
                    heapq.heappush(pq, (new_dist, v))

        throughput_dist[node] = dist

    # Group destinations by cloud
    cloud_dests = defaultdict(list)
    cloud_nodes = defaultdict(list)

    for node in all_nodes:
        if node.startswith('aws'):
            cloud_nodes['aws'].append(node)
        elif node.startswith('azure'):
            cloud_nodes['azure'].append(node)
        elif node.startswith('gcp'):
            cloud_nodes['gcp'].append(node)

    for dst in dsts:
        if dst.startswith('aws'):
            cloud_dests['aws'].append(dst)
        elif dst.startswith('azure'):
            cloud_dests['azure'].append(dst)
        elif dst.startswith('gcp'):
            cloud_dests['gcp'].append(dst)

    # Find best hubs for each cloud
    cloud_hubs = {}
    hub_costs = {}

    for cloud, dest_list in cloud_dests.items():
        if not dest_list:
            continue

        candidate_hubs = cloud_nodes[cloud]
        if not candidate_hubs:
            continue

        best_hub = None
        best_cost = float('inf')

        for hub in candidate_hubs:
            if cost_dist[src][hub] == float('inf'):
                continue

            total_cost = 0
            valid = True

            for dst in dest_list:
                if dst == hub:
                    total_cost += cost_dist[src][hub]
                else:
                    if cost_dist[hub][dst] == float('inf'):
                        valid = False
                        break
                    total_cost += cost_dist[src][hub] + cost_dist[hub][dst]

            if valid and total_cost < best_cost:
                best_cost = total_cost
                best_hub = hub

        if best_hub:
            cloud_hubs[cloud] = best_hub
            hub_costs[cloud] = best_cost

    # Generate multiple path options for each destination
    dst_options = {}

    for dst in dsts:
        options = []

        # Option 1: Direct path
        if cost_dist[src][dst] < float('inf'):
            # Reconstruct path
            path = []
            current = dst
            while current is not None:
                path.append(current)
                current = cost_pred[src][current]
            path.reverse()
            options.append(('direct', cost_dist[src][dst], path))

        # Option 2: Via cloud hub
        dst_cloud = None
        if dst.startswith('aws'):
            dst_cloud = 'aws'
        elif dst.startswith('azure'):
            dst_cloud = 'azure'
        elif dst.startswith('gcp'):
            dst_cloud = 'gcp'

        if dst_cloud and dst_cloud in cloud_hubs:
            hub = cloud_hubs[dst_cloud]
            if hub != dst and cost_dist[src][hub] < float('inf') and cost_dist[hub][dst] < float('inf'):
                # Reconstruct src->hub path
                path1 = []
                current = hub
                while current is not None:
                    path1.append(current)
                    current = cost_pred[src][current]
                path1.reverse()

                # Reconstruct hub->dst path
                path2 = []
                current = dst
                while current is not None and current != hub:
                    path2.append(current)
                    current = cost_pred[hub][current]
                if current == hub:
                    path2.append(hub)
                    path2.reverse()
                    # Combine paths
                    full_path = path1[:-1] + path2
                    total_cost = cost_dist[src][hub] + cost_dist[hub][dst]
                    options.append(('hub', total_cost, full_path))

        # Sort by cost
        options.sort(key=lambda x: x[1])
        dst_options[dst] = options

    # For each partition, assign paths with load balancing
    # Use a weighted round-robin based on cost
    for partition in range(num_partitions):
        for dst in dsts:
            options = dst_options[dst]
            if not options:
                continue

            # Simple round-robin assignment
            option_idx = partition % len(options)
            _, _, path = options[option_idx]

            # Add all edges in path
            for i in range(len(path) - 1):
                u, v = path[i], path[i+1]
                edge_data = G[u][v]
                bc_topology.append_dst_partition_path(dst, partition, [u, v, edge_data])

    return bc_topology

