def search_algorithm(src: str, dsts: List[str], G: nx.DiGraph, num_partitions: int) -> BroadCastTopology:
    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # Remove source from destinations if present
    dsts = [d for d in dsts if d != src]
    if not dsts:
        return bc_topology

    # Precompute shortest paths and distances from source to all nodes
    all_nodes = list(G.nodes())
    dist_from_src = {}
    prev_from_src = {}
    pq = [(0, src, None)]

    while pq:
        d, u, p = heapq.heappop(pq)
        if u in dist_from_src:
            continue
        dist_from_src[u] = d
        prev_from_src[u] = p
        for v, data in G[u].items():
            new_dist = d + data['cost']
            if v not in dist_from_src or new_dist < dist_from_src.get(v, float('inf')):
                heapq.heappush(pq, (new_dist, v, u))

    # Reconstruct paths from source to all nodes
    paths_from_src = {}
    for node in all_nodes:
        if node not in dist_from_src:
            continue
        path = []
        curr = node
        while curr is not None:
            path.append(curr)
            curr = prev_from_src.get(curr)
        paths_from_src[node] = list(reversed(path))

    # Group destinations by cloud
    cloud_groups = defaultdict(list)
    for dst in dsts:
        if dst.startswith('aws'):
            cloud_groups['aws'].append(dst)
        elif dst.startswith('azure'):
            cloud_groups['azure'].append(dst)
        elif dst.startswith('gcp'):
            cloud_groups['gcp'].append(dst)

    # Find best hub for each cloud
    cloud_hubs = {}
    for cloud, nodes in cloud_groups.items():
        if not nodes:
            continue

        best_hub = None
        best_cost = float('inf')

        # Consider each node in the cloud as potential hub
        for hub_candidate in G.nodes():
            if not hub_candidate.startswith(cloud):
                continue
            if hub_candidate not in paths_from_src:
                continue

            # Calculate total cost: source->hub + sum(hub->each_destination)
            total_cost = dist_from_src[hub_candidate] * len(nodes)

            # Precompute distances from hub to all nodes in same cloud
            hub_dist = {}
            hub_pq = [(0, hub_candidate)]
            while hub_pq:
                d, u = heapq.heappop(hub_pq)
                if u in hub_dist:
                    continue
                hub_dist[u] = d
                for v, data in G[u].items():
                    if not v.startswith(cloud):
                        continue
                    new_dist = d + data['cost']
                    if v not in hub_dist or new_dist < hub_dist.get(v, float('inf')):
                        heapq.heappush(hub_pq, (new_dist, v))

            # Add hub->destination costs
            valid = True
            for dst in nodes:
                if dst == hub_candidate:
                    continue
                if dst not in hub_dist:
                    valid = False
                    break
                total_cost += hub_dist[dst]

            if valid and total_cost < best_cost:
                best_cost = total_cost
                best_hub = hub_candidate

        if best_hub:
            cloud_hubs[cloud] = best_hub

    # For each destination, prepare candidate paths
    candidate_paths = {}
    for dst in dsts:
        candidates = []

        # Direct path
        if dst in paths_from_src:
            direct_path = paths_from_src[dst]
            direct_cost = dist_from_src[dst]
            candidates.append((direct_cost, direct_path, 'direct'))

        # Hub path if applicable
        dst_cloud = None
        if dst.startswith('aws'):
            dst_cloud = 'aws'
        elif dst.startswith('azure'):
            dst_cloud = 'azure'
        elif dst.startswith('gcp'):
            dst_cloud = 'gcp'

        if dst_cloud and dst_cloud in cloud_hubs:
            hub = cloud_hubs[dst_cloud]
            if hub != dst and hub in paths_from_src:
                # Get path from hub to dst
                hub_to_dst_dist = {}
                hub_to_dst_prev = {}
                hub_pq = [(0, hub, None)]

                while hub_pq:
                    d, u, p = heapq.heappop(hub_pq)
                    if u in hub_to_dst_dist:
                        continue
                    hub_to_dst_dist[u] = d
                    hub_to_dst_prev[u] = p
                    for v, data in G[u].items():
                        new_dist = d + data['cost']
                        if v not in hub_to_dst_dist or new_dist < hub_to_dst_dist.get(v, float('inf')):
                            heapq.heappush(hub_pq, (new_dist, v, u))

                if dst in hub_to_dst_dist:
                    # Reconstruct hub->dst path
                    hub_path = []
                    curr = dst
                    while curr is not None:
                        hub_path.append(curr)
                        curr = hub_to_dst_prev.get(curr)
                    hub_path = list(reversed(hub_path))

                    # Combine with src->hub path
                    src_to_hub_path = paths_from_src[hub]
                    if src_to_hub_path[-1] == hub_path[0]:
                        full_path = src_to_hub_path[:-1] + hub_path
                    else:
                        full_path = src_to_hub_path + hub_path

                    total_cost = dist_from_src[hub] + hub_to_dst_dist[dst]
                    candidates.append((total_cost, full_path, 'hub'))

        # Sort by cost and keep best few
        candidates.sort(key=lambda x: x[0])
        candidate_paths[dst] = [c[1] for c in candidates[:min(3, len(candidates))]]

    # Assign partitions to paths using round-robin for load balancing
    for partition in range(num_partitions):
        for dst in dsts:
            if dst not in candidate_paths or not candidate_paths[dst]:
                # Fallback to direct path if available
                if dst in paths_from_src:
                    path = paths_from_src[dst]
                else:
                    continue
            else:
                # Round-robin selection among candidate paths
                path_idx = partition % len(candidate_paths[dst])
                path = candidate_paths[dst][path_idx]

            # Add path segments
            for i in range(len(path) - 1):
                u, v = path[i], path[i + 1]
                bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])

    return bc_topology

