from collections import defaultdict

def search_algorithm(src: str, dsts: List[str], G: nx.DiGraph, num_partitions: int) -> BroadCastTopology:
    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # Precompute all-pairs shortest paths for key nodes
    all_nodes = list(G.nodes())
    cloud_prefixes = ['aws', 'azure', 'gcp']

    # Find cloud hubs (lowest cost from src within each cloud)
    cloud_hubs = {}
    for prefix in cloud_prefixes:
        cloud_nodes = [n for n in all_nodes if n.startswith(prefix)]
        if not cloud_nodes:
            continue

        best_hub = None
        best_cost = float('inf')
        for node in cloud_nodes:
            try:
                cost = nx.dijkstra_path_length(G, src, node, weight='cost')
                if cost < best_cost:
                    best_cost = cost
                    best_hub = node
            except:
                continue
        if best_hub:
            cloud_hubs[prefix] = best_hub

    # For each destination, find multiple candidate paths
    candidate_paths = {}
    for dst in dsts:
        paths = []

        # Direct path (src -> dst)
        try:
            direct_path = nx.dijkstra_path(G, src, dst, weight='cost')
            paths.append(('direct', direct_path))
        except:
            pass

        # Cloud hub path if applicable
        for prefix, hub in cloud_hubs.items():
            if dst.startswith(prefix) and hub != dst:
                try:
                    path1 = nx.dijkstra_path(G, src, hub, weight='cost')
                    path2 = nx.dijkstra_path(G, hub, dst, weight='cost')
                    # Merge paths
                    if path1[-1] == path2[0]:
                        hub_path = path1[:-1] + path2
                    else:
                        hub_path = path1 + path2
                    paths.append((f'hub_{prefix}', hub_path))
                except:
                    continue

        # Store top 3 unique paths by cost
        unique_paths = []
        seen = set()
        for name, path in sorted(paths, key=lambda x: sum(G[u][v]['cost'] for u, v in zip(x[1][:-1], x[1][1:]))):
            path_tuple = tuple(path)
            if path_tuple not in seen:
                seen.add(path_tuple)
                unique_paths.append(path)
                if len(unique_paths) >= 3:
                    break
        candidate_paths[dst] = unique_paths

    # Assign partitions to balance across available paths
    for dst in dsts:
        if not candidate_paths.get(dst):
            continue

        paths = candidate_paths[dst]
        num_paths = len(paths)

        for partition in range(num_partitions):
            # Round-robin assignment
            selected_path = paths[partition % num_paths]

            # Add all edges in the path
            for i in range(len(selected_path) - 1):
                u, v = selected_path[i], selected_path[i+1]
                if G.has_edge(u, v):
                    edge_data = G[u][v]
                    bc_topology.append_dst_partition_path(dst, partition, [u, v, edge_data])

    return bc_topology

