def search_algorithm(src: str, dsts: List[str], G: nx.DiGraph, num_partitions: int) -> BroadCastTopology:
    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # Precompute shortest paths from source to all destinations by cost
    src_to_dst_shortest_paths = {}
    for dst in dsts:
        try:
            path = nx.dijkstra_path(G, src, dst, weight='cost')
            src_to_dst_shortest_paths[dst] = path
        except nx.NetworkXNoPath:
            src_to_dst_shortest_paths[dst] = None

    # Group destinations by cloud
    cloud_destinations = defaultdict(list)
    for dst in dsts:
        if dst.startswith("aws"):
            cloud_destinations["aws"].append(dst)
        elif dst.startswith("azure"):
            cloud_destinations["azure"].append(dst)
        elif dst.startswith("gcp"):
            cloud_destinations["gcp"].append(dst)

    # Identify potential 'entry points' for each cloud (cheapest path from src to any node in that cloud)
    cloud_entry_points = {}
    for cloud, dest_list in cloud_destinations.items():
        if not dest_list:
            continue

        min_cloud_cost = float('inf')
        best_entry_node = None

        # Iterate through all nodes in the graph to find the best entry to this cloud
        for node in G.nodes():
            if node.startswith(cloud):
                try:
                    path_to_node = nx.dijkstra_path(G, src, node, weight='cost')
                    cost_to_node = sum(G[path_to_node[i]][path_to_node[i+1]]['cost'] for i in range(len(path_to_node) - 1))
                    if cost_to_node < min_cloud_cost:
                        min_cloud_cost = cost_to_node
                        best_entry_node = node
                except nx.NetworkXNoPath:
                    pass

        if best_entry_node:
            cloud_entry_points[cloud] = best_entry_node

    # Assign paths for each partition
    for partition in range(num_partitions):
        # Simple strategy: Cycle through direct, then cloud-entry-point routing
        strategy = partition % 2 

        if strategy == 0:
            # Strategy 1: Use direct shortest paths for all destinations
            for dst in dsts:
                path = src_to_dst_shortest_paths.get(dst)
                if path:
                    for i in range(len(path) - 1):
                        u, v = path[i], path[i+1]
                        edge_data = G[u][v]
                        bc_topology.append_dst_partition_path(dst, partition, [u, v, edge_data])
        else:
            # Strategy 2: Use cloud entry points for destinations within a cloud
            for cloud, dest_list in cloud_destinations.items():
                entry_point = cloud_entry_points.get(cloud)
                if not entry_point:
                    # Fallback to direct path if no entry point found for this cloud
                    for dst in dest_list:
                        path = src_to_dst_shortest_paths.get(dst)
                        if path:
                            for i in range(len(path) - 1):
                                u, v = path[i], path[i+1]
                                edge_data = G[u][v]
                                bc_topology.append_dst_partition_path(dst, partition, [u, v, edge_data])
                    continue

                # Path from source to the cloud's entry point
                try:
                    src_to_entry_path = nx.dijkstra_path(G, src, entry_point, weight='cost')
                    for i in range(len(src_to_entry_path) - 1):
                        u, v = src_to_entry_path[i], src_to_entry_path[i+1]
                        edge_data = G[u][v]
                        # Add this segment to all destinations in the cloud for this partition
                        for dst in dest_list:
                            bc_topology.append_dst_partition_path(dst, partition, [u, v, edge_data])
                except nx.NetworkXNoPath:
                    # If src cannot reach entry_point, fallback to direct paths for this cloud
                    for dst in dest_list:
                        path = src_to_dst_shortest_paths.get(dst)
                        if path:
                            for i in range(len(path) - 1):
                                u, v = path[i], path[i+1]
                                edge_data = G[u][v]
                                bc_topology.append_dst_partition_path(dst, partition, [u, v, edge_data])
                    continue

                # Paths from the entry point to each destination within the cloud
                for dst in dest_list:
                    if dst == entry_point:
                        continue
                    try:
                        entry_to_dst_path = nx.dijkstra_path(G, entry_point, dst, weight='cost')
                        for i in range(len(entry_to_dst_path) - 1):
                            u, v = entry_to_dst_path[i], entry_to_dst_path[i+1]
                            edge_data = G[u][v]
                            bc_topology.append_dst_partition_path(dst, partition, [u, v, edge_data])
                    except nx.NetworkXNoPath:
                        # If entry_point cannot reach dst, fallback to direct path for this dst
                        path = src_to_dst_shortest_paths.get(dst)
                        if path:
                            for i in range(len(path) - 1):
                                u, v = path[i], path[i+1]
                                edge_data = G[u][v]
                                bc_topology.append_dst_partition_path(dst, partition, [u, v, edge_data])

    # Ensure all destinations have at least one path for each partition (fallback to direct)
    for dst in dsts:
        for partition in range(num_partitions):
            if not bc_topology.paths.get(dst, {}).get(str(partition), []):
                path = src_to_dst_shortest_paths.get(dst)
                if path:
                    for i in range(len(path) - 1):
                        u, v = path[i], path[i+1]
                        edge_data = G[u][v]
                        bc_topology.append_dst_partition_path(dst, partition, [u, v, edge_data])

    return bc_topology

