    # For each cloud, find a representative hub (cheapest node that can reach others)
    cloud_hubs = {}
    for cloud, nodes in cloud_groups.items():
        if not nodes:
            continue
        # Find cheapest node in cloud group
        cheapest_node = min(nodes, key=lambda n: G.nodes[n].get('cost', float('inf')) if n in G.nodes else float('inf'))
        # If this node is reachable from source, use it as hub
        if shortest_paths.get(cheapest_node) is not None:
            cloud_hubs[cloud] = cheapest_node

    # Find alternative paths for load balancing
    def get_alternative_paths(src_node, dst_node, max_paths=3):
        try:
            paths = []
            path_gen = nx.shortest_simple_paths(G, src_node, dst_node, weight='cost')
            for i, path in enumerate(path_gen):
                if i >= max_paths:
                    break
                paths.append(path)
            return paths
        except:
            return [[]]

    # Assign paths to each partition
    for partition in range(num_partitions):
        # For each destination, assign a path
        for dst in dsts:
