            elif dst.startswith('azure'):
                dst_cloud = 'azure'
            elif dst.startswith('gcp'):
                dst_cloud = 'gcp'

            # Use intra-cloud hub if available and beneficial
            if dst_cloud and dst_cloud in cloud_hubs:
                hub = cloud_hubs[dst_cloud]
                if hub != dst and shortest_paths.get(hub) is not None:
                    # Path via hub
                    try:
                        intra_path = nx.shortest_path(G, hub, dst, weight='cost')
                        # Combine source -> hub and hub -> dst
                        if dst in shortest_paths:
                            full_path = shortest_paths[hub][:-1] + intra_path
                            selected_path = full_path
                            path_strategy = 'hub'
                    except:
                        pass

            # Fall back to direct path
            if selected_path is None and shortest_paths.get(dst):
                selected_path = shortest_paths[dst]

            # If still no path, use fallback
            if selected_path is None:
                # Just use a path from the graph if possible
                try:
                    fallback_path = nx.dijkstra_path(G, src, dst, weight='cost')
                    selected_path = fallback_path
                except:
                    continue

            # Add edges to topology
            for i in range(len(selected_path) - 1):
                u, v = selected_path[i], selected_path[i + 1]
                bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])

    return bc_topology

