def search_algorithm(src: str, dsts: List[str], G: nx.DiGraph, num_partitions: int) -> BroadCastTopology:
    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # Precompute shortest paths and costs for all destinations
    shortest_paths = {}
    shortest_costs = {}

    for dst in dsts:
        try:
            path = nx.dijkstra_path(G, src, dst, weight='cost')
            cost = sum(G[path[i]][path[i+1]]['cost'] for i in range(len(path)-1))
            shortest_paths[dst] = path
            shortest_costs[dst] = cost
        except nx.NetworkXNoPath:
            shortest_paths[dst] = None
            shortest_costs[dst] = float('inf')

    # For each destination, create multiple diverse paths to enable load balancing
    dst_alternatives = {}

    for dst in dsts:
        if shortest_paths[dst] is None:
            dst_alternatives[dst] = [(None, float('inf'))]
            continue

        base_path = shortest_paths[dst]
        alternatives = [(base_path, shortest_costs[dst])]

        # Generate alternative paths by removing edges from the shortest path
        for i in range(min(2, len(base_path) - 1)):
            H = G.copy()
            H.remove_edge(base_path[i], base_path[i+1])
            try:
                alt_path = nx.dijkstra_path(H, src, dst, weight='cost')
                if alt_path != base_path:
                    alt_cost = sum(G[alt_path[j]][alt_path[j+1]]['cost'] for j in range(len(alt_path)-1))
                    alternatives.append((alt_path, alt_cost))
            except:
                continue

        # Add hub-based paths for intra-cloud optimization
        # Find nodes with high degree that could serve as hubs
        hub_candidates = [n for n, d in G.degree() if d > 2 and n != src and n != dst]
        for hub in hub_candidates[:2]:  # Try top 2 hubs
            try:
                path1 = nx.dijkstra_path(G, src, hub, weight='cost')
                path2 = nx.dijkstra_path(G, hub, dst, weight='cost')
                if len(path1) > 1 and len(path2) > 1:
                    combined = path1[:-1] + path2
                    combined_cost = sum(G[combined[i]][combined[i+1]]['cost'] for i in range(len(combined)-1))
                    alternatives.append((combined, combined_cost))
            except:
                continue

        # Sort alternatives by cost and keep top 3
        alternatives.sort(key=lambda x: x[1])
        dst_alternatives[dst] = alternatives[:3]

    # Assign partitions to paths for optimal distribution
    for partition in range(num_partitions):
        for dst in dsts:
            # Select path based on partition number to distribute load
            path_idx = partition % len(dst_alternatives[dst])
            path, _ = dst_alternatives[dst][path_idx]

            if path is None:
                # Fallback to direct path
                path = shortest_paths.get(dst)
                if path is None:
                    continue

            # Add path segments to topology
            for i in range(len(path) - 1):
                u, v = path[i], path[i+1]
                if G.has_edge(u, v):
                    edge_data = G[u][v]
                    bc_topology.append_dst_partition_path(dst, partition, [u, v, edge_data])

    return bc_topology

