            for i in range(len(base_path) - 1):
                temp_G = G.copy()
                u, v = base_path[i], base_path[i+1]
                temp_G.remove_edge(u, v)

                try:
                    alt_path = nx.dijkstra_path(temp_G, src, dst, weight='cost')
                    # Ensure it's different and valid
