from collections import defaultdict

def search_algorithm(src: str, dsts: List[str], G: nx.DiGraph, num_partitions: int) -> BroadCastTopology:
    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # Precompute all-pairs shortest paths for critical nodes
    all_nodes = list(G.nodes())
    critical_nodes = set([src] + dsts)

    # Add cloud entry candidates
    for node in all_nodes:
        if node.startswith("aws") or node.startswith("azure") or node.startswith("gcp"):
            critical_nodes.add(node)

    # Compute shortest paths between all critical nodes
    cost_paths = {}
    for u in critical_nodes:
        for v in critical_nodes:
            if u == v:
                continue
            try:
                path = nx.dijkstra_path(G, u, v, weight='cost')
                cost_paths[(u, v)] = path
            except:
                cost_paths[(u, v)] = None

    # Group destinations by cloud
    cloud_dests = defaultdict(list)
    for dst in dsts:
        if dst.startswith("aws"):
            cloud_dests["aws"].append(dst)
        elif dst.startswith("azure"):
            cloud_dests["azure"].append(dst)
        elif dst.startswith("gcp"):
            cloud_dests["gcp"].append(dst)

    # Find optimal entry points for each cloud from source
    cloud_entry = {}
    for cloud in ["aws", "azure", "gcp"]:
        best_cost = float('inf')
        best_node = None
        for node in critical_nodes:
            if node.startswith(cloud):
                path_key = (src, node)
                if path_key in cost_paths and cost_paths[path_key]:
                    # Compute path cost
                    path = cost_paths[path_key]
                    cost = sum(G[path[i]][path[i+1]]['cost'] for i in range(len(path)-1))
                    if cost < best_cost:
                        best_cost = cost
                        best_node = node
        cloud_entry[cloud] = (best_node, best_cost) if best_node else None

    # Find intra-cloud hubs that minimize maximum distance to destinations
    cloud_hubs = {}
    for cloud in ["aws", "azure", "gcp"]:
        if cloud not in cloud_dests or not cloud_dests[cloud]:
            continue

        cloud_nodes = [n for n in critical_nodes if n.startswith(cloud)]
        if not cloud_nodes:
            continue

        best_hub = None
        best_score = float('inf')

        for hub in cloud_nodes:
            # Cost from source to hub
            src_to_hub_key = (src, hub)
            if src_to_hub_key not in cost_paths or not cost_paths[src_to_hub_key]:
                continue

            src_to_hub_cost = sum(G[cost_paths[src_to_hub_key][i]][cost_paths[src_to_hub_key][i+1]]['cost'] 
                                 for i in range(len(cost_paths[src_to_hub_key])-1))

            # Maximum cost from hub to destinations in same cloud
            max_hub_to_dest = 0
            valid = True

            for dest in cloud_dests[cloud]:
                if dest == hub:
                    continue
                hub_to_dest_key = (hub, dest)
                if hub_to_dest_key not in cost_paths or not cost_paths[hub_to_dest_key]:
                    valid = False
                    break

                hub_to_dest_cost = sum(G[cost_paths[hub_to_dest_key][i]][cost_paths[hub_to_dest_key][i+1]]['cost']
                                      for i in range(len(cost_paths[hub_to_dest_key])-1))
                max_hub_to_dest = max(max_hub_to_dest, hub_to_dest_cost)

            if valid:
                score = src_to_hub_cost + max_hub_to_dest
                if score < best_score:
                    best_score = score
                    best_hub = hub

        cloud_hubs[cloud] = best_hub

    # Define routing strategies for different partitions
    for partition in range(num_partitions):
        # Use 4 different strategies cyclically
        strategy = partition % 4

        if strategy == 0:
            # Direct cheapest paths
            for dst in dsts:
                path_key = (src, dst)
                if path_key in cost_paths and cost_paths[path_key]:
                    path = cost_paths[path_key]
                    for i in range(len(path)-1):
                        u, v = path[i], path[i+1]
                        bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])

        elif strategy == 1:
            # Cloud entry point routing
            for dst in dsts:
                dst_cloud = None
                for cloud in ["aws", "azure", "gcp"]:
                    if dst.startswith(cloud):
                        dst_cloud = cloud
                        break

                if dst_cloud and dst_cloud in cloud_entry and cloud_entry[dst_cloud]:
                    entry_node = cloud_entry[dst_cloud][0]

                    # Source to entry node
                    path1_key = (src, entry_node)
                    if path1_key in cost_paths and cost_paths[path1_key]:
                        path1 = cost_paths[path1_key]
                        for i in range(len(path1)-1):
                            u, v = path1[i], path1[i+1]
                            bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])

                    # Entry node to destination if different
                    if entry_node != dst:
                        path2_key = (entry_node, dst)
                        if path2_key in cost_paths and cost_paths[path2_key]:
                            path2 = cost_paths[path2_key]
                            for i in range(len(path2)-1):
                                u, v = path2[i], path2[i+1]
                                bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])
                else:
                    # Fallback to direct
                    path_key = (src, dst)
                    if path_key in cost_paths and cost_paths[path_key]:
                        path = cost_paths[path_key]
                        for i in range(len(path)-1):
                            u, v = path[i], path[i+1]
                            bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])

        elif strategy == 2:
            # Cloud hub routing with broadcast within cloud
            for cloud in ["aws", "azure", "gcp"]:
                if cloud not in cloud_hubs or cloud not in cloud_dests:
                    continue

                hub = cloud_hubs[cloud]
                if not hub:
                    continue

                # Source to hub
                path1_key = (src, hub)
                if path1_key in cost_paths and cost_paths[path1_key]:
                    path1 = cost_paths[path1_key]
                    for i in range(len(path1)-1):
                        u, v = path1[i], path1[i+1]
                        edge_data = G[u][v]
                        # Broadcast to all destinations in this cloud
                        for dst in cloud_dests[cloud]:
                            bc_topology.append_dst_partition_path(dst, partition, [u, v, edge_data])

                # Hub to each destination in cloud
                for dst in cloud_dests[cloud]:
                    if dst == hub:
                        continue
                    path2_key = (hub, dst)
                    if path2_key in cost_paths and cost_paths[path2_key]:
                        path2 = cost_paths[path2_key]
                        for i in range(len(path2)-1):
                            u, v = path2[i], path2[i+1]
                            bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])

        else:  # strategy == 3
            # Hybrid: mix of direct and hub routing based on cloud
            for dst in dsts:
                dst_cloud = None
                for cloud in ["aws", "azure", "gcp"]:
                    if dst.startswith(cloud):
                        dst_cloud = cloud
                        break

                # Use hub for aws if available, otherwise direct
                use_hub = (dst_cloud == "aws" and dst_cloud in cloud_hubs and cloud_hubs[dst_cloud])

                if use_hub:
                    hub = cloud_hubs[dst_cloud]
                    # Source to hub
                    path1_key = (src, hub)
                    if path1_key in cost_paths and cost_paths[path1_key]:
                        path1 = cost_paths[path1_key]
                        for i in range(len(path1)-1):
                            u, v = path1[i], path1[i+1]
                            bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])

                    # Hub to destination
                    if hub != dst:
                        path2_key = (hub, dst)
                        if path2_key in cost_paths and cost_paths[path2_key]:
                            path2 = cost_paths[path2_key]
                            for i in range(len(path2)-1):
                                u, v = path2[i], path2[i+1]
                                bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])
                else:
                    # Direct path
                    path_key = (src, dst)
                    if path_key in cost_paths and cost_paths[path_key]:
                        path = cost_paths[path_key]
                        for i in range(len(path)-1):
                            u, v = path[i], path[i+1]
                            bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])

    # Ensure all (dst, partition) pairs have paths
    for dst in dsts:
        for partition in range(num_partitions):
            dst_dict = bc_topology.paths.get(dst, {})
            partition_list = dst_dict.get(str(partition), [])

            if not partition_list:
                # Use direct path as fallback
                path_key = (src, dst)
