        cloud_hubs[cloud] = cheapest_dst

    # Assign paths to partitions
    for partition in range(num_partitions):
        # Strategy: alternate between direct routing and cloud hub routing
        strategy = partition % 2

        if strategy == 0:
            # Direct routing: each destination gets its shortest path
            for dst in dsts:
                if dst in shortest_paths and shortest_paths[dst][1]:
                    path = shortest_paths[dst][1]
                    for i in range(len(path)-1):
