            # Hub routing: use hubs for each cloud
            for cloud, hub in cloud_hubs.items():
                # For each destination in this cloud, use the hub
                for dst in cloud_dests.get(cloud, []):
                    if dst == hub:
                        # Direct path to hub
                        if dst in shortest_paths and shortest_paths[dst][1]:
                            path = shortest_paths[dst][1]
                            for i in range(len(path)-1):
                                u, v = path[i], path[i+1]
