                                u, v = hub_path[i], hub_path[i+1]
                                if u == src:
                                    bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])

                        # Add path from hub to dst
                        try:
                            path_to_dst = nx.dijkstra_path(G, hub, dst, weight='cost')
                            for i in range(len(path_to_dst)-1):
