            cost = sum(G[path[i]][path[i+1]]['cost'] for i in range(len(path)-1))
            shortest_paths[dst] = path
            shortest_costs[dst] = cost
        except nx.NetworkXNoPath:
            shortest_paths[dst] = None
            shortest_costs[dst] = float('inf')

    # Generate diverse paths for each destination
    dst_alternatives = {}

    for dst in dsts:
        if shortest_paths[dst] is None:
            dst_alternatives[dst] = [None]
            continue

        base_path = shortest_paths[dst]
        alternatives = [base_path]

        # Strategy 1: Find alternative paths by removing edges from base path
        for i in range(min(2, len(base_path) - 1)):
            H = G.copy()
            H.remove_edge(base_path[i], base_path[i+1])
            try:
                alt_path = nx.dijkstra_path(H, src, dst, weight='cost')
                if alt_path != base_path and alt_path not in alternatives:
                    alternatives.append(alt_path)
            except:
                continue

        # Strategy 2: Use hub-based paths for cross-cloud optimization
        # Find hub nodes that have high degree and are not source or destination
        hub_candidates = [n for n, d in G.degree() if d > 2 and n != src and n != dst]

        # Try to create paths through hub nodes that are likely to reduce cost
        for hub in hub_candidates[:2]:  # Try top 2 hubs
            try:
                path1 = nx.dijkstra_path(G, src, hub, weight='cost')
                path2 = nx.dijkstra_path(G, hub, dst, weight='cost')
                if len(path1) > 1 and len(path2) > 1:
                    combined = path1[:-1] + path2
                    if combined not in alternatives:
                        alternatives.append(combined)
            except:
                continue

        # Calculate cost for each path
        paths_info = []
        for path in alternatives:
            if path is None:
                total_cost = float('inf')
            else:
                total_cost = sum(G[path[i]][path[i+1]]['cost'] for i in range(len(path)-1))
            paths_info.append((total_cost, path))

        # Sort by cost and keep only top 3 paths
        paths_info.sort(key=lambda x: x[0])
        dst_alternatives[dst] = [info[1] for info in paths_info[:3]]

    # Assign partitions using a cost-aware strategy
    for partition in range(num_partitions):
        for dst in dsts:
            if dst not in dst_alternatives or not dst_alternatives[dst]:
                # Fallback to shortest path if no alternatives
                path = shortest_paths.get(dst)
                if path:
                    for i in range(len(path)-1):
                        u, v = path[i], path[i+1]
                        bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])
            else:
                # Assign paths in a way that balances cost and bandwidth
                path_idx = partition % len(dst_alternatives[dst])
                path = dst_alternatives[dst][path_idx]

                # If path is None, fallback to shortest path
                if path is None:
                    path = shortest_paths.get(dst)

                if path:
                    for i in range(len(path)-1):
                        u, v = path[i], path[i+1]
                        bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])

    return bc_topology

