from collections import defaultdict

def search_algorithm(src: str, dsts: List[str], G: nx.DiGraph, num_partitions: int) -> BroadCastTopology:
    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # Precompute all-pairs shortest paths by cost within each cloud
    nodes_by_cloud = defaultdict(list)
    for node in G.nodes():
        if node.startswith('aws'):
            nodes_by_cloud['aws'].append(node)
        elif node.startswith('azure'):
            nodes_by_cloud['azure'].append(node)
        elif node.startswith('gcp'):
            nodes_by_cloud['gcp'].append(node)

    # Find the cheapest hub in each cloud from source
    cloud_hubs = {}
    hub_paths = {}

    for cloud, nodes in nodes_by_cloud.items():
        best_cost = float('inf')
        best_hub = None
        best_path = None

        for node in nodes:
            try:
                path = nx.dijkstra_path(G, src, node, weight='cost')
                cost = sum(G[path[i]][path[i+1]]['cost'] for i in range(len(path)-1))
                if cost < best_cost:
                    best_cost = cost
                    best_hub = node
                    best_path = path
            except:
                continue

        if best_hub:
            cloud_hubs[cloud] = best_hub
            hub_paths[best_hub] = (best_path, best_cost)

    # For each destination, compute multiple path options
    dst_path_options = {}

    for dst in dsts:
        if dst == src:
            dst_path_options[dst] = [([], 0.0)]
            continue

        options = []

        # Option 1: Direct path from source
        try:
            direct_path = nx.dijkstra_path(G, src, dst, weight='cost')
            direct_cost = sum(G[direct_path[i]][direct_path[i+1]]['cost'] 
                            for i in range(len(direct_path)-1))
            options.append((direct_path, direct_cost))
        except:
            pass

        # Option 2: Via cloud hub
        dst_cloud = None
        for cloud in ['aws', 'azure', 'gcp']:
            if dst.startswith(cloud):
                dst_cloud = cloud
                break

        if dst_cloud and dst_cloud in cloud_hubs:
            hub = cloud_hubs[dst_cloud]
            if hub != dst:
                try:
                    # Path from source to hub
                    src_to_hub_path, hub_cost = hub_paths[hub]

                    # Path from hub to destination
                    hub_to_dst_path = nx.dijkstra_path(G, hub, dst, weight='cost')
                    intra_cost = sum(G[hub_to_dst_path[i]][hub_to_dst_path[i+1]]['cost']
                                   for i in range(len(hub_to_dst_path)-1))

                    # Combine paths (avoid duplicate hub)
                    combined_path = src_to_hub_path[:-1] + hub_to_dst_path
                    total_cost = hub_cost + intra_cost
                    options.append((combined_path, total_cost))
                except:
                    pass

        # Option 3: Alternative paths via different hubs
        for cloud, hub in cloud_hubs.items():
            if cloud == dst_cloud or hub == dst:
                continue

            try:
                # Source to alternative hub
                src_to_alt_path, alt_hub_cost = hub_paths[hub]

                # Alternative hub to destination
                alt_to_dst_path = nx.dijkstra_path(G, hub, dst, weight='cost')
                cross_cost = sum(G[alt_to_dst_path[i]][alt_to_dst_path[i+1]]['cost']
                               for i in range(len(alt_to_dst_path)-1))

                combined_path = src_to_alt_path[:-1] + alt_to_dst_path
                total_cost = alt_hub_cost + cross_cost
                options.append((combined_path, total_cost))
            except:
                pass

        # Remove duplicates and sort by cost
        unique_options = []
        seen_paths = set()
        for path, cost in options:
            path_tuple = tuple(path)
            if path_tuple not in seen_paths:
                seen_paths.add(path_tuple)
                unique_options.append((path, cost))

        unique_options.sort(key=lambda x: x[1])
        dst_path_options[dst] = unique_options

    # Optimize partition assignment using cost-weighted distribution
    for dst in dsts:
        if not dst_path_options[dst]:
            continue

        options = dst_path_options[dst]

        # Calculate weights for each path (inverse cost squared)
        weights = []
        total_weight = 0

        for _, cost in options:
            weight = 1.0 / (cost * cost + 0.001)
            weights.append(weight)
            total_weight += weight

        # Normalize weights
        if total_weight > 0:
            weights = [w / total_weight for w in weights]
        else:
            weights = [1.0 / len(options)] * len(options)

        # Assign partitions to paths based on weights
        path_assignments = []
        cumulative = 0

        for i, (path, _) in enumerate(options):
            share = weights[i]
            count = max(1, int(share * num_partitions))
            path_assignments.append((path, count))
            cumulative += count

        # Distribute remaining partitions
        remaining = num_partitions - cumulative
        if remaining > 0:
            # Add to cheapest paths first
            for i in range(min(remaining, len(options))):
                path, count = path_assignments[i]
                path_assignments[i] = (path, count + 1)

        # Build the actual partition paths
        partition_idx = 0
        for path, count in path_assignments:
            for _ in range(count):
                if partition_idx >= num_partitions:
                    break

                if path:  # Path might be empty for src==dst
                    for i in range(len(path) - 1):
                        u, v = path[i], path[i + 1]
                        bc_topology.append_dst_partition_path(dst, partition_idx, 
                                                             [u, v, G[u][v]])
                partition_idx += 1

        # Fill any remaining partitions with cheapest path
        while partition_idx < num_partitions:
            cheapest_path, _ = options[0]
            if cheapest_path:
                for i in range(len(cheapest_path) - 1):
                    u, v = cheapest_path[i], cheapest_path[i + 1]
                    bc_topology.append_dst_partition_path(dst, partition_idx,
                                                         [u, v, G[u][v]])
            partition_idx += 1

    return bc_topology

