    shortest_paths = {}
    for dst in dsts:
        if dst == src:
            continue
        try:
            path = nx.dijkstra_path(G, src, dst, weight='cost')
            shortest_paths[dst] = path
        except nx.NetworkXNoPath:
            shortest_paths[dst] = None

    # Generate diverse paths for each destination
    def get_path_options(dst: str, base_path: List[str]) -> List[Tuple[float, List[str]]]:
        if base_path is None:
            return [(float('inf'), None)]

        options = [(0.0, base_path)]

        # Try alternative paths by removing edges
        for i in range(len(base_path) - 1):
            H = G.copy()
            H.remove_edge(base_path[i], base_path[i+1])
            try:
                alt_path = nx.dijkstra_path(H, src, dst, weight='cost')
                if alt_path != base_path:
                    cost = sum(G[alt_path[j]][alt_path[j+1]]['cost'] for j in range(len(alt_path)-1))
                    options.append((cost, alt_path))
            except:
                continue

        # Try paths via common hubs
        hub_candidates = []
        for node in G.nodes():
            if node != src and node != dst:
                # Filter for hubs that connect multiple clouds
                neighbors = list(G.neighbors(node))
                if len(neighbors) >= 2:
                    hub_candidates.append(node)

        for hub in hub_candidates[:3]:  # Top 3 hubs
            try:
                path1 = nx.dijkstra_path(G, src, hub, weight='cost')
                path2 = nx.dijkstra_path(G, hub, dst, weight='cost')
                if len(path1) > 1 and len(path2) > 1:
                    combined = path1[:-1] + path2
                    cost = sum(G[combined[j]][combined[j+1]]['cost'] for j in range(len(combined)-1))
                    options.append((cost, combined))
            except:
                continue

        # Sort by cost and limit to 5 options
        options.sort(key=lambda x: x[0])
        return options[:5]

    # Get path options for all destinations
    dst_options = {}
    for dst in dsts:
        if dst == src:
            continue
        base_path = shortest_paths.get(dst)
        dst_options[dst] = get_path_options(dst, base_path)

    # Assign partitions to paths
    for partition in range(num_partitions):
        for dst in dsts:
            if dst == src:
                continue

            if dst not in dst_options or not dst_options[dst]:
                # Fallback to direct path
                path = shortest_paths.get(dst)
                if path:
                    for i in range(len(path)-1):
                        u, v = path[i], path[i+1]
                        bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])
            else:
                # Select path based on partition number
                option_index = partition % len(dst_options[dst])
                cost, path = dst_options[dst][option_index]

                if path:
                    for i in range(len(path)-1):
                        u, v = path[i], path[i+1]
                        bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])

    return bc_topology

