def search_algorithm(src: str, dsts: List[str], G: nx.DiGraph, num_partitions: int) -> BroadCastTopology:
    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # Remove self from destinations if present
    dsts = [d for d in dsts if d != src]

    # Precompute shortest path trees from source
    pred, dist = nx.dijkstra_predecessor_and_distance(G, src, weight='cost')

    def get_shortest_path(target):
        if target not in pred:
            return None
        path = [target]
        while path[-1] != src:
            if not pred[path[-1]]:
                return None
            path.append(pred[path[-1]][0])
        return list(reversed(path))

    # Find multiple good paths using edge perturbation
    def find_alternative_paths(src_node, dst_node, base_path, k=3):
        paths = [base_path]

        # Try removing each edge in base path
        for i in range(len(base_path)-1):
            if len(paths) >= k:
                break
            H = G.copy()
            H.remove_edge(base_path[i], base_path[i+1])
            try:
                alt_path = nx.dijkstra_path(H, src_node, dst_node, weight='cost')
                if alt_path not in paths:
                    paths.append(alt_path)
            except:
                pass

        # Try via different intermediate nodes
        cloud_nodes = defaultdict(list)
        for node in G.nodes():
            if node == src_node or node == dst_node:
                continue
            if node.startswith('aws'):
                cloud_nodes['aws'].append(node)
            elif node.startswith('azure'):
                cloud_nodes['azure'].append(node)
            elif node.startswith('gcp'):
                cloud_nodes['gcp'].append(node)

        # Sample some intermediate nodes
        candidates = []
        for cloud in ['aws', 'azure', 'gcp']:
            candidates.extend(cloud_nodes[cloud][:2])  # Take first 2 from each

        for intermediate in candidates:
            if len(paths) >= k:
                break
            try:
                path1 = nx.dijkstra_path(G, src_node, intermediate, weight='cost')
                path2 = nx.dijkstra_path(G, intermediate, dst_node, weight='cost')
                combined = path1[:-1] + path2
                if combined not in paths:
                    paths.append(combined)
            except:
                pass

        return paths[:k]

    # For each destination, collect candidate paths
    dst_candidates = {}
    for dst in dsts:
        base_path = get_shortest_path(dst)
        if not base_path:
            continue

        # Get alternative paths
        all_paths = find_alternative_paths(src, dst, base_path, k=min(4, num_partitions))

        # Calculate path costs and throughputs
        path_info = []
        for path in all_paths:
            total_cost = 0
            min_throughput = float('inf')
            for i in range(len(path)-1):
                u, v = path[i], path[i+1]
                total_cost += G[u][v]['cost']
                min_throughput = min(min_throughput, G[u][v]['throughput'])

            # Score prioritizing cost but considering throughput
            score = total_cost * 0.95 + (1.0 / (min_throughput + 0.1)) * 0.05
            path_info.append((score, total_cost, min_throughput, path))

        # Sort by score and keep best ones
        path_info.sort(key=lambda x: x[0])
        dst_candidates[dst] = [info[3] for info in path_info]

    # Distribute partitions using cost-based weighting
    for dst in dsts:
        if dst not in dst_candidates or not dst_candidates[dst]:
            # Fallback to shortest path
            base_path = get_shortest_path(dst)
            if base_path:
                for partition in range(num_partitions):
                    for i in range(len(base_path)-1):
                        u, v = base_path[i], base_path[i+1]
                        bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])
            continue

        paths = dst_candidates[dst]
        if len(paths) == 1:
            # Single path for all partitions
            for partition in range(num_partitions):
                for i in range(len(paths[0])-1):
                    u, v = paths[0][i], paths[0][i+1]
                    bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])
            continue

        # Calculate path costs
        path_costs = []
        for path in paths:
            cost = sum(G[path[i]][path[i+1]]['cost'] for i in range(len(path)-1))
            path_costs.append(cost)

        # Use exponential weighting to favor cheaper paths
        min_cost = min(path_costs)
        weights = []
        for cost in path_costs:
            # Strong bias toward cheaper paths
            weight = 1.0 / (1.0 + (cost - min_cost) * 10)
            weights.append(weight)

        total_weight = sum(weights)
        if total_weight == 0:
            probs = [1.0/len(paths)] * len(paths)
        else:
            probs = [w/total_weight for w in weights]

        # Assign partitions deterministically
        cum_probs = [0] * len(probs)
        cum = 0
        for i, p in enumerate(probs):
            cum += p
            cum_probs[i] = cum

        path_assignments = [0] * len(paths)
        for p in range(num_partitions):
            r = p / num_partitions  # Evenly spaced
            for i in range(len(cum_probs)):
                if r <= cum_probs[i]:
                    path_assignments[i] += 1
                    break

        # Distribute partitions
        partition_idx = 0
        for path_idx, count in enumerate(path_assignments):
            path = paths[path_idx]
            for _ in range(count):
                if partition_idx >= num_partitions:
                    break
                for i in range(len(path)-1):
                    u, v = path[i], path[i+1]
                    bc_topology.append_dst_partition_path(dst, partition_idx, [u, v, G[u][v]])
                partition_idx += 1

        # Handle any remaining partitions
        while partition_idx < num_partitions:
            path = paths[0]  # Use cheapest path
            for i in range(len(path)-1):
                u, v = path[i], path[i+1]
                bc_topology.append_dst_partition_path(dst, partition_idx, [u, v, G[u][v]])
            partition_idx += 1

    return bc_topology

