def search_algorithm(src: str, dsts: List[str], G: nx.DiGraph, num_partitions: int) -> BroadCastTopology:
    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # Filter out source from destinations
    dsts = [d for d in dsts if d != src]
    if not dsts:
        return bc_topology

    # Precompute all-pairs shortest paths for key nodes
    def compute_path_cost(path):
        return sum(G[path[i]][path[i+1]]['cost'] for i in range(len(path)-1))

    # Get cloud information for each node
    def get_cloud(node):
        if node.startswith('aws'):
            return 'aws'
        elif node.startswith('azure'):
            return 'azure'
        elif node.startswith('gcp'):
            return 'gcp'
        return 'unknown'

    # Find potential hub nodes within each cloud
    cloud_nodes = defaultdict(list)
    for node in G.nodes():
        cloud = get_cloud(node)
        cloud_nodes[cloud].append(node)

    # Find best hub for each cloud (lowest cost from source)
    cloud_hubs = {}
    for cloud, nodes in cloud_nodes.items():
        best_hub = None
        best_cost = float('inf')
        for node in nodes:
            try:
                path = nx.dijkstra_path(G, src, node, weight='cost')
                cost = compute_path_cost(path)
                if cost < best_cost:
                    best_cost = cost
                    best_hub = (path, cost)
            except:
                continue
        if best_hub:
            cloud_hubs[cloud] = best_hub

    # For each destination, find multiple candidate paths
    candidate_paths = defaultdict(list)

    for dst in dsts:
        dst_cloud = get_cloud(dst)

        # 1. Direct shortest path by cost
        try:
            direct_path = nx.dijkstra_path(G, src, dst, weight='cost')
            direct_cost = compute_path_cost(direct_path)
            candidate_paths[dst].append((direct_cost, direct_path))
        except:
            pass

        # 2. Via cloud hub (if available and different from destination)
        if dst_cloud in cloud_hubs and cloud_hubs[dst_cloud][0][-1] != dst:
            hub_path, hub_cost = cloud_hubs[dst_cloud]
            hub_node = hub_path[-1]
            try:
                hub_to_dst = nx.dijkstra_path(G, hub_node, dst, weight='cost')
                via_hub_cost = hub_cost + compute_path_cost(hub_to_dst)
                via_hub_path = hub_path[:-1] + hub_to_dst
                candidate_paths[dst].append((via_hub_cost, via_hub_path))
            except:
                pass

        # 3. Alternative paths via edge perturbation
        if candidate_paths[dst]:
            base_path = min(candidate_paths[dst], key=lambda x: x[0])[1]

            # Try removing edges from base path
            for i in range(len(base_path)-1):
                if len(candidate_paths[dst]) >= num_partitions:
                    break
                H = G.copy()
                u, v = base_path[i], base_path[i+1]
                H.remove_edge(u, v)
                try:
                    alt_path = nx.dijkstra_path(H, src, dst, weight='cost')
                    alt_cost = compute_path_cost(alt_path)
                    if alt_path != base_path:
                        candidate_paths[dst].append((alt_cost, alt_path))
                except:
                    pass

        # 4. Via other cloud hubs (for cross-cloud optimization)
        for cloud, (hub_path, hub_cost) in cloud_hubs.items():
            if cloud == dst_cloud or len(candidate_paths[dst]) >= num_partitions:
                continue
            hub_node = hub_path[-1]
            try:
                cross_path = nx.dijkstra_path(G, hub_node, dst, weight='cost')
                cross_cost = hub_cost + compute_path_cost(cross_path)
                cross_full_path = hub_path[:-1] + cross_path
                candidate_paths[dst].append((cross_cost, cross_full_path))
            except:
                pass

        # Remove duplicates and sort by cost
        unique_paths = {}
        for cost, path in candidate_paths[dst]:
            path_tuple = tuple(path)
            if path_tuple not in unique_paths or cost < unique_paths[path_tuple][0]:
                unique_paths[path_tuple] = (cost, path)

        candidate_paths[dst] = sorted(unique_paths.values(), key=lambda x: x[0])

        # Ensure we have at least one path
        if not candidate_paths[dst]:
            # Try any path (not necessarily cheapest)
            try:
                path = nx.dijkstra_path(G, src, dst)
                cost = compute_path_cost(path)
                candidate_paths[dst].append((cost, path))
            except:
                continue

    # Assign partitions using cost-weighted distribution
    for dst in dsts:
        if dst not in candidate_paths or not candidate_paths[dst]:
            continue

        paths = [p for _, p in candidate_paths[dst][:num_partitions]]
        costs = [c for c, _ in candidate_paths[dst][:num_partitions]]

        if len(paths) == 1:
            # Single path for all partitions
            path = paths[0]
            for partition in range(num_partitions):
                for i in range(len(path)-1):
                    u, v = path[i], path[i+1]
                    bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])
            continue

        # Calculate weights using exponential cost scaling
        min_cost = min(costs)
        weights = []
        for cost in costs:
            # Strong bias toward cheaper paths
            if cost == min_cost:
                weights.append(1.0)
            else:
                penalty = (cost - min_cost) * 5.0
                weights.append(1.0 / (1.0 + penalty))

        # Normalize weights
        total_weight = sum(weights)
        if total_weight > 0:
            probs = [w / total_weight for w in weights]
        else:
            probs = [1.0 / len(paths)] * len(paths)

        # Assign partitions deterministically
        assignments = [0] * len(paths)
        remaining = num_partitions

        # First pass: assign minimum to each path
        for i in range(len(paths)):
            min_assign = 1 if remaining > len(paths) - i else 0
            assignments[i] = min_assign
            remaining -= min_assign

        # Distribute remaining partitions based on probabilities
        if remaining > 0:
            cumulative = 0
            thresholds = []
            for p in probs:
                cumulative += p
                thresholds.append(cumulative)

            for p_idx in range(remaining):
                position = (p_idx / remaining) if remaining > 0 else 0
                for i, threshold in enumerate(thresholds):
                    if position <= threshold:
                        assignments[i] += 1
                        break

        # Apply assignments
        partition_idx = 0
        for path_idx, count in enumerate(assignments):
            path = paths[path_idx]
            for _ in range(count):
                if partition_idx >= num_partitions:
                    break
                for i in range(len(path)-1):
                    u, v = path[i], path[i+1]
                    bc_topology.append_dst_partition_path(dst, partition_idx, [u, v, G[u][v]])
                partition_idx += 1

        # Fill any remaining partitions with cheapest path
        while partition_idx < num_partitions:
            path = paths[0]
            for i in range(len(path)-1):
                u, v = path[i], path[i+1]
                bc_topology.append_dst_partition_path(dst, partition_idx, [u, v, G[u][v]])
            partition_idx += 1

    return bc_topology

