def search_algorithm(src: str, dsts: List[str], G: nx.DiGraph, num_partitions: int) -> BroadCastTopology:
    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # Precompute shortest paths by cost for all destinations
    shortest_paths = {}
    for dst in dsts:
        try:
            shortest_paths[dst] = nx.dijkstra_path(G, src, dst, weight='cost')
        except nx.NetworkXNoPath:
            shortest_paths[dst] = None

    # For each destination, find diverse paths and assign partitions
    for dst in dsts:
        if shortest_paths[dst] is None:
            continue

        # Get the shortest path for this destination
        base_path = shortest_paths[dst]

        # Collect alternative paths using different strategies
        alternative_paths = []

        # Strategy 1: Use shortest simple paths (excluding base path)
        try:
            path_generator = nx.shortest_simple_paths(G, src, dst, weight='cost')
            next(path_generator)  # Skip the shortest path

            for i, path in enumerate(path_generator):
                if i >= 2:  # Limit to 2 additional paths
                    break
                alternative_paths.append(path)
        except:
            pass

        # Strategy 2: Try to find paths with different throughput characteristics
        if not alternative_paths:
            try:
                # Find path based on inverse throughput (lower throughput = higher cost for throughput)
                throughput_path = nx.dijkstra_path(G, src, dst, 
                    weight=lambda u, v, d: 1.0/d['throughput'] if d['throughput'] > 0 else float('inf'))
                if throughput_path != base_path:
                    alternative_paths.append(throughput_path)
            except:
                pass

        # Combine base and alternative paths
        all_paths = [base_path] + alternative_paths

        # Ensure we have enough paths (repeat base if needed)
        while len(all_paths) < num_partitions:
            all_paths.append(base_path)

        # Assign partitions to paths using round-robin
        for partition in range(num_partitions):
            path_idx = partition % len(all_paths)
            selected_path = all_paths[path_idx]

            # Add each edge in the path to topology
            for i in range(len(selected_path) - 1):
                u, v = selected_path[i], selected_path[i + 1]
                if G.has_edge(u, v):
                    bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])

    return bc_topology

