    # Compute shortest path distances from source
    distances = {}
    for node in G.nodes():
        try:
            distances[node] = nx.dijkstra_path_length(G, src, node, weight='cost')
        except:
            distances[node] = float('inf')

    # Group destinations by cloud
    cloud_dests = defaultdict(list)
    for dst in dsts:
        if dst.startswith("aws"):
            cloud_dests["aws"].append(dst)
        elif dst.startswith("azure"):
            cloud_dests["azure"].append(dst)
        elif dst.startswith("gcp"):
            cloud_dests["gcp"].append(dst)

    # Find best hub for each cloud
    cloud_hubs = {}
    hub_costs = {}

    for cloud, dest_list in cloud_dests.items():
        if not dest_list:
            continue

        best_hub = None
        best_cost = float('inf')
        best_intra_costs = {}

        # Consider each node in the cloud as potential hub
        for node in G.nodes():
            if not node.startswith(cloud):
                continue

            try:
                # Cost from source to hub
                src_to_hub = distances[node]
                if src_to_hub == float('inf'):
                    continue

                # Calculate total cost from hub to all destinations in cloud
                total_intra_cost = 0
                intra_costs = {}
                valid = True

                for dst in dest_list:
                    if dst == node:
                        intra_costs[dst] = 0
                        continue

                    try:
                        cost = nx.dijkstra_path_length(G, node, dst, weight='cost')
                        intra_costs[dst] = cost
                        total_intra_cost += cost
                    except:
                        valid = False
                        break

                if valid:
                    total_cost = src_to_hub * len(dest_list) + total_intra_cost
                    if total_cost < best_cost:
                        best_cost = total_cost
                        best_hub = node
                        best_intra_costs = intra_costs.copy()
            except:
                continue

        if best_hub:
            cloud_hubs[cloud] = best_hub
            hub_costs[cloud] = best_intra_costs

    # For each destination, generate candidate paths
    dst_paths = {}

    for dst in dsts:
        if dst == src:
            dst_paths[dst] = [[src]]
            continue

        candidates = []

        # 1. Direct path
        try:
            direct_path = nx.dijkstra_path(G, src, dst, weight='cost')
            candidates.append(direct_path)
        except:
            pass

        # 2. Path via cloud hub if applicable
        dst_cloud = None
        for cloud in ["aws", "azure", "gcp"]:
            if dst.startswith(cloud):
                dst_cloud = cloud
                break

        if dst_cloud and dst_cloud in cloud_hubs and dst in hub_costs[dst_cloud]:
            hub = cloud_hubs[dst_cloud]
            try:
                # Source to hub path
                src_to_hub = nx.dijkstra_path(G, src, hub, weight='cost')
                # Hub to destination path
                hub_to_dst = nx.dijkstra_path(G, hub, dst, weight='cost')

                # Combine avoiding duplicate hub node
                if src_to_hub[-1] == hub_to_dst[0]:
                    combined = src_to_hub + hub_to_dst[1:]
                else:
                    combined = src_to_hub + hub_to_dst

                if combined not in candidates:
                    candidates.append(combined)
            except:
                pass

        # 3. Alternative paths (up to 3 total)
        if candidates:
            # Try to find one more alternative if we have capacity
            if len(candidates) < 3:
                try:
                    # Find k-shortest paths
                    paths_gen = nx.shortest_simple_paths(G, src, dst, weight='cost')
                    count = 0
                    for path in paths_gen:
                        if path not in candidates:
                            candidates.append(path)
                            count += 1
                            if count >= 3 - len(candidates):
                                break
                except:
                    pass

        # If no candidates found, try any path
        if not candidates:
            try:
                # Fallback: use any path (e.g., unweighted shortest)
                fallback = nx.shortest_path(G, src, dst)
                candidates.append(fallback)
            except:
                # Last resort: direct edge if exists
                if G.has_edge(src, dst):
                    candidates.append([src, dst])
                else:
                    candidates.append([src])

        dst_paths[dst] = candidates

    # Assign partitions to paths with load balancing
    # Create partition assignments based on path diversity
    assignments = {}

    # For each destination, create a list of path indices for each partition
    for dst in dsts:
        if dst == src:
            assignments[dst] = [0] * num_partitions
            continue

        paths = dst_paths[dst]
        if not paths:
            assignments[dst] = [0] * num_partitions
            continue

        # Calculate costs for each path
        path_costs = []
        for path in paths:
            cost = 0
            for i in range(len(path) - 1):
                cost += G[path[i]][path[i+1]]['cost']
            path_costs.append(cost)

        # Sort paths by cost
        sorted_indices = sorted(range(len(paths)), key=lambda i: path_costs[i])

        # Assign partitions to paths in round-robin fashion
        path_assignments = []
        for i in range(num_partitions):
            path_idx = sorted_indices[i % len(sorted_indices)]
            path_assignments.append(path_idx)

        assignments[dst] = path_assignments

    # Build the topology
    for partition in range(num_partitions):
        for dst in dsts:
            if dst == src:
                continue

            path_idx = assignments[dst][partition]
            path = dst_paths[dst][path_idx]

            for i in range(len(path) - 1):
                u, v = path[i], path[i+1]
                edge_data = G[u][v]
                bc_topology.append_dst_partition_path(dst, partition, [u, v, edge_data])

    return bc_topology

import networkx as nx
from typing import List, Dict, Tuple
from collections import defaultdict
import heapq

def search_algorithm(src: str, dsts: List[str], G: nx.DiGraph, num_partitions: int) -> BroadCastTopology:
    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # Helper to get cloud provider from node name
    def get_cloud(node: str) -> str:
        if 'aws' in node.lower():
            return 'aws'
        elif 'azure' in node.lower():
            return 'azure'
        elif 'gcp' in node.lower():
            return 'gcp'
        return 'other'

    # Precompute shortest paths and distances from source
    distances = {}
    predecessors = {}

    # Dijkstra from source to all nodes
    pq = [(0, src, None)]
    while pq:
        dist, node, pred = heapq.heappop(pq)
        if node in distances:
            continue
        distances[node] = dist
        predecessors[node] = pred

        for neighbor in G.successors(node):
            if neighbor not in distances:
                edge_cost = G[node][neighbor]['cost']
                heapq.heappush(pq, (dist + edge_cost, neighbor, node))

    # Reconstruct paths from source to all nodes
    src_paths = {}
    for dst in G.nodes():
        if dst not in distances:
            continue
        path = []
        curr = dst
        while curr is not None:
            path.append(curr)
            curr = predecessors[curr]
        src_paths[dst] = list(reversed(path))

    # Find best intra-cloud hubs
    cloud_nodes = defaultdict(list)
    for node in G.nodes():
        cloud_nodes[get_cloud(node)].append(node)

    cloud_hubs = {}
    hub_intra_paths = {}

    for cloud, nodes in cloud_nodes.items():
        if not nodes:
            continue

        best_hub = None
        best_avg_cost = float('inf')
        best_paths = {}

        # Try each node in cloud as potential hub
        for hub in nodes:
            if hub not in distances:
                continue

            total_intra_cost = 0
            intra_paths = {}
            valid = True

            for node in nodes:
                if node == hub:
                    continue

                # Find shortest path from hub to node within cloud
                try:
                    path = nx.dijkstra_path(G, hub, node, weight='cost')
                    cost = sum(G[path[i]][path[i+1]]['cost'] for i in range(len(path)-1))
                    total_intra_cost += cost
                    intra_paths[node] = (path, cost)
                except:
                    valid = False
                    break

            if valid:
                avg_cost = (distances[hub] * len(nodes) + total_intra_cost) / len(nodes)
                if avg_cost < best_avg_cost:
                    best_avg_cost = avg_cost
                    best_hub = hub
                    best_paths = intra_paths

        if best_hub:
            cloud_hubs[cloud] = best_hub
            hub_intra_paths[best_hub] = best_paths

    # Generate multiple path options for each destination
    dst_path_options = {}

    for dst in dsts:
        if dst == src:
            continue

        options = []
        dst_cloud = get_cloud(dst)

        # Option 1: Direct shortest path
        if dst in src_paths:
            direct_path = src_paths[dst]
            direct_cost = distances[dst]
            options.append((direct_cost, direct_path, 'direct'))

        # Option 2: Via same-cloud hub
        if dst_cloud in cloud_hubs:
            hub = cloud_hubs[dst_cloud]
            if hub != dst and hub in src_paths and dst in hub_intra_paths.get(hub, {}):
                hub_to_dst_path, hub_to_dst_cost = hub_intra_paths[hub][dst]
                combined_path = src_paths[hub][:-1] + hub_to_dst_path
                combined_cost = distances[hub] + hub_to_dst_cost
                options.append((combined_cost, combined_path, 'intra_hub'))

        # Option 3: Via other cloud hubs (inter-cloud)
        for other_cloud, other_hub in cloud_hubs.items():
            if other_cloud == dst_cloud or other_hub == dst:
                continue

            if other_hub in src_paths:
                # Check if path exists from other_hub to dst
                try:
                    inter_path = nx.dijkstra_path(G, other_hub, dst, weight='cost')
                    inter_cost = sum(G[inter_path[i]][inter_path[i+1]]['cost'] 
                                    for i in range(len(inter_path)-1))
                    combined_path = src_paths[other_hub][:-1] + inter_path
                    combined_cost = distances[other_hub] + inter_cost
                    options.append((combined_cost, combined_path, f'inter_{other_cloud}'))
                except:
                    continue

        # Option 4: Alternative paths via edge removal
        if dst in src_paths and len(src_paths[dst]) > 2:
            base_path = src_paths[dst]
            # Try removing first few edges
            for i in range(min(3, len(base_path)-1)):
                H = G.copy()
                H.remove_edge(base_path[i], base_path[i+1])
                try:
                    alt_path = nx.dijkstra_path(H, src, dst, weight='cost')
                    alt_cost = sum(G[alt_path[j]][alt_path[j+1]]['cost'] 
                                 for j in range(len(alt_path)-1))
                    options.append((alt_cost, alt_path, f'alt_{i}'))
                except:
                    continue

        # Sort by cost and deduplicate
        options.sort(key=lambda x: x[0])
        seen_paths = set()
        unique_options = []

        for cost, path, label in options:
            path_tuple = tuple(path)
            if path_tuple not in seen_paths:
                seen_paths.add(path_tuple)
                unique_options.append((cost, path))
                if len(unique_options) >= min(num_partitions, 5):
                    break

        dst_path_options[dst] = unique_options if unique_options else []

    # Assign partitions to paths using cost-aware load balancing
    # First, ensure each destination has at least one path
    for dst in dsts:
        if not dst_path_options.get(dst):
            if dst in src_paths:
                cost = distances[dst]
                dst_path_options[dst] = [(cost, src_paths[dst])]
            else:
                # Last resort: find any path
                try:
                    path = nx.dijkstra_path(G, src, dst, weight='cost')
                    cost = sum(G[path[i]][path[i+1]]['cost'] for i in range(len(path)-1))
                    dst_path_options[dst] = [(cost, path)]
                except:
                    continue

    # Assign partitions with weighted distribution favoring cheaper paths
    for partition in range(num_partitions):
        for dst in dsts:
            if dst not in dst_path_options or not dst_path_options[dst]:
                continue

            options = dst_path_options[dst]
            num_options = len(options)

            if num_options == 1:
                path_idx = 0
            else:
                # Create weights: cheaper paths get higher probability
                costs = [opt[0] for opt in options]
                max_cost = max(costs)
                min_cost = min(costs)

                if max_cost == min_cost:
                    weights = [1] * num_options
                else:
                    # Invert costs: cheaper -> higher weight
                    weights = [(max_cost - cost + 1) for cost in costs]

                # Deterministic selection based on partition
                total_weight = sum(weights)
                target = (partition * 31) % total_weight  # Deterministic hash

                cumulative = 0
                path_idx = 0
                for i, w in enumerate(weights):
                    cumulative += w
                    if cumulative > target:
                        path_idx = i
                        break

            cost, path = options[path_idx]

            # Add path segments to topology
            for i in range(len(path)-1):
                u, v = path[i], path[i+1]
                bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])

    return bc_topology

import networkx as nx
from typing import List, Dict, Tuple
from collections import defaultdict
import heapq

def search_algorithm(src: str, dsts: List[str], G: nx.DiGraph, num_partitions: int) -> BroadCastTopology:
    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # Precompute shortest paths from source to all destinations
    shortest_paths = {}
    shortest_costs = {}

    for dst in dsts:
        try:
            path = nx.dijkstra_path(G, src, dst, weight='cost')
            path_cost = nx.dijkstra_path_length(G, src, dst, weight='cost')
            shortest_paths[dst] = path
            shortest_costs[dst] = path_cost
        except nx.NetworkXNoPath:
            shortest_paths[dst] = []
            shortest_costs[dst] = float('inf')

    # Find best alternative paths for load balancing
    alternative_paths = {}
    for dst in dsts:
        alternatives = []
        if shortest_paths[dst]:
            alternatives.append((shortest_costs[dst], 0, shortest_paths[dst]))

            # Find up to 3 alternative paths
            try:
                paths_gen = nx.shortest_simple_paths(G, src, dst, weight='cost')
                count = 1
                for path in paths_gen:
                    if count >= 4:
                        break
                    path_cost = sum(G[u][v]['cost'] for u, v in zip(path[:-1], path[1:]))
                    alternatives.append((path_cost, count, path))
                    count += 1
            except:
                pass

            # Sort by cost
            alternatives.sort(key=lambda x: x[0])
            alternative_paths[dst] = [(cost, idx, path) for cost, idx, path in alternatives]
        else:
            alternative_paths[dst] = []

    # Assign paths to partitions
    # Strategy: use the cheapest path for most partitions, spread alternatives for better throughput
    for partition in range(num_partitions):
        for dst in dsts:
            paths_for_dst = alternative_paths.get(dst, [])

            if not paths_for_dst:
                # Fallback to direct path if available
                if dst in shortest_paths and shortest_paths[dst]:
                    path = shortest_paths[dst]
                    for i in range(len(path) - 1):
                        u, v = path[i], path[i + 1]
                        bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])
                continue

            # Prefer cheaper paths but distribute partitions to avoid congestion
            # Use first path for majority, others for remaining partitions
            path_index = partition % len(paths_for_dst)
            _, _, path = paths_for_dst[path_index]

            # Add all edges in path
            for i in range(len(path) - 1):
                u, v = path[i], path[i + 1]
                if G.has_edge(u, v):
                    bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])

    # Ensure all destinations have valid paths for all partitions
    for dst in dsts:
        for partition in range(num_partitions):
            if not bc_topology.paths.get(dst, {}).get(str(partition), []):
                # Fallback to the shortest path for this destination
                if dst in shortest_paths and shortest_paths[dst]:
                    path = shortest_paths[dst]
                    for i in range(len(path) - 1):
                        u, v = path[i], path[i + 1]
                        bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])

    return bc_topology
